insert into aura_exercise_catalog (id, payload, updated_at) values
  ('9E8E17E6-CA59-5EA1-A55E-5FC71C606E69'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9E8E17E6-CA59-5EA1-A55E-5FC71C606E69","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"3/4 Sit-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A6D3E5BC-9821-5C4F-9C9C-8CA7DB0EF95E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BF37F2E8-6B43-53E3-B478-8DD6E60D3E65'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"BF37F2E8-6B43-53E3-B478-8DD6E60D3E65","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"45° Side Bend","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your arms extended straight down by your sides.","Keeping your back straight and your core engaged, slowly bend your torso to one side, lowering your hand towards your knee.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2C14B49B-E921-552C-9438-D61406C90769","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6D153532-53A0-540F-882E-39C0E7AF4128'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"6D153532-53A0-540F-882E-39C0E7AF4128","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Air Bike","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your hands placed behind your head.","Lift your legs off the ground and bend your knees at a 90-degree angle.","Bring your right elbow towards your left knee while simultaneously straightening your right leg.","Return to the starting position and repeat the movement on the opposite side, bringing your left elbow towards your right knee while straightening your left leg.","Continue alternating sides in a pedaling motion for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DE05DB4B-B782-5B78-AC5D-C30B883ECEF6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0B3FF7FC-DF90-5E2A-B9F2-DD18C40B181D'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"0B3FF7FC-DF90-5E2A-B9F2-DD18C40B181D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings","Glutes"],"name":"All Fours Squad Stretch","notes":"","plannedSets":3,"proTips":["Start on all fours with your hands directly under your shoulders and your knees directly under your hips.","Extend one leg straight back, keeping your knee bent and your foot flexed.","Slowly lower your hips towards the ground, feeling a stretch in your quads.","Hold this position for 20-30 seconds.","Switch legs and repeat the stretch on the other side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"2BC5549B-E4F0-5D63-8965-DD2C7DA10102","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('6A31F84E-62BD-5700-A61D-B79AC1A4C0F1'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"6A31F84E-62BD-5700-A61D-B79AC1A4C0F1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Alternate Heel Touchers","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms straight out to the sides, parallel to the ground.","Engaging your abs, lift your shoulders off the ground and reach your right hand towards your right heel.","Return to the starting position and repeat on the left side, reaching your left hand towards your left heel.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E867B6A3-7409-5DC7-AF7F-59DFE288252A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D80F88F8-2C74-59F9-8D49-789BB347A23F'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Cable","hint":"","id":"D80F88F8-2C74-59F9-8D49-789BB347A23F","imageURL":"","isCable":true,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids"],"name":"Alternate Lateral Pulldown","notes":"","plannedSets":3,"proTips":["Sit on the cable machine with your back straight and feet flat on the ground.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Lean back slightly and pull the handles towards your chest, squeezing your shoulder blades together.","Pause for a moment at the peak of the movement, then slowly release the handles back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"0E44ABEA-36AF-5AE9-9501-B121B934E3A6","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"D4B8CE97-DE58-5EB3-BE05-C1DB5DD03ACC","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('62B5D2B7-7E60-5803-902A-2537ACD10F73'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"62B5D2B7-7E60-5803-902A-2537ACD10F73","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Ankle Stabilizers"],"name":"Ankle Circles","notes":"","plannedSets":3,"proTips":["Sit on the ground with your legs extended in front of you.","Lift one leg off the ground and rotate your ankle in a circular motion.","Perform the desired number of circles in one direction, then switch to the other direction.","Repeat with the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"C6743908-9289-5DEB-BECA-A532EB637483","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('E5B17E5A-11BA-541F-8BFB-125D41D8B221'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"E5B17E5A-11BA-541F-8BFB-125D41D8B221","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Archer Pull Up","notes":"","plannedSets":3,"proTips":["Start by hanging from a pull-up bar with an overhand grip, slightly wider than shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","As you pull yourself up, bend one arm and bring your elbow towards your side, while keeping the other arm straight.","Continue pulling until your chin is above the bar and your bent arm is fully flexed.","Lower yourself back down with control, straightening the bent arm and repeating the movement on the other side.","Alternate sides with each repetition."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F5408223-8F16-5116-A60F-03A6533C0C2A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F236BA6A-4398-5380-B17C-A730770893B9'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"F236BA6A-4398-5380-B17C-A730770893B9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders","Core"],"name":"Archer Push Up","notes":"","plannedSets":3,"proTips":["Start in a push-up position with your hands slightly wider than shoulder-width apart.","Extend one arm straight out to the side, parallel to the ground.","Lower your body by bending your elbows, keeping your back straight and core engaged.","Push back up to the starting position.","Repeat on the other side, extending the opposite arm out to the side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AC0D3375-961E-5476-81EE-EDA9738CC79F","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B64F0AE4-B386-5720-80CF-E2DED6AE1540'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B64F0AE4-B386-5720-80CF-E2DED6AE1540","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Back"],"name":"Arm Slingers Hanging Bent Knee Legs","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your knees bent at a 90-degree angle.","Engage your core and lift your knees towards your chest, bringing them as close to your elbows as possible.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5A0D3ED9-AD8A-5E43-B210-786A1336B07D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E45FA48B-D46C-528B-9B95-032DA2924414'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"E45FA48B-D46C-528B-9B95-032DA2924414","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Back"],"name":"Arm Slingers Hanging Straight Legs","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your legs straight down.","Engage your core and lift your legs up in front of you until they are parallel to the ground.","Hold for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E6359EC0-FE58-5023-8377-51F128572E0B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1258207B-D4DC-570D-83C3-A3276A6C16DD'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"1258207B-D4DC-570D-83C3-A3276A6C16DD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Calves"],"name":"Arms Apart Circular Toe Touch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and arms extended to the sides.","Keeping your legs straight, bend forward at the waist and reach down towards your toes with your right hand.","As you reach down, simultaneously lift your left leg straight up behind you, maintaining balance.","Return to the starting position and repeat the movement with your left hand reaching towards your toes and your right leg lifting up behind you.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"72A3A163-3DF7-5FA7-BD6E-0E697553F7C1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('05A07719-19EE-502B-BB4C-9474FF849861'::uuid, '{"category":"Core","difficulty":"Intermediate","equipment":"Bodyweight","hint":"","id":"05A07719-19EE-502B-BB4C-9474FF849861","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Arms Overhead Full Sit-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms overhead, keeping them straight.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is upright.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6BA6B8AE-33A2-5689-8475-C6BDF8EC81FB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('02E2205E-86A4-527B-8EC0-71A8C286D78E'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Machine","hint":"","id":"02E2205E-86A4-527B-8EC0-71A8C286D78E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Assisted Chest Dip (Kneeling)","notes":"","plannedSets":3,"proTips":["Adjust the machine to your desired height and secure your knees on the pad.","Grasp the handles with your palms facing down and your arms fully extended.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Pause for a moment, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"92CDB1FD-AC17-5498-A25F-4E200B22ADEA","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"DEC345ED-001D-5F17-B104-28E9BE133573","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('16A6DF59-E14E-5D32-BC87-C588B2181C50'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"16A6DF59-E14E-5D32-BC87-C588B2181C50","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Assisted Hanging Knee Raise","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core muscles and lift your knees towards your chest, bending at the hips and knees.","Pause for a moment at the top of the movement, squeezing your abs.","Slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"F6E430E4-1C58-55AA-8449-BC3B17AA6754","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"C9261206-F8E4-5A09-AF97-386A69E19F50","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('72C46F22-CB77-5FE7-9F65-03EA9E959168'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"72C46F22-CB77-5FE7-9F65-03EA9E959168","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Lower Back"],"name":"Assisted Hanging Knee Raise With Throw Down","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your arms fully extended and your palms facing away from you.","Engage your core and lift your knees towards your chest, keeping your legs together.","Once your knees are at chest level, explosively throw your legs down towards the ground, extending them fully.","Allow your legs to swing back up and repeat the movement for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"9C1CC5B9-3935-5D6D-B385-4642F348B348","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"E3FB91DE-0AC8-5D93-AE4D-D9CE0143EEB1","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BDAD531C-79AC-5F44-97FE-A30CFF8F1393'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"BDAD531C-79AC-5F44-97FE-A30CFF8F1393","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings"],"name":"Assisted Lying Calves Stretch","notes":"","plannedSets":3,"proTips":["Lie on your back with your legs extended.","Bend one knee and place your foot flat on the ground.","Using your hands or a towel, gently pull your toes towards your body, feeling a stretch in your calf.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat on the other leg."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"6D28CBFF-D986-574D-B9DE-55D7C8076A33","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('6C6DD634-BBCD-5DAA-AE5B-E0B454AF783F'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"6C6DD634-BBCD-5DAA-AE5B-E0B454AF783F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings"],"name":"Assisted Lying Glutes Stretch","notes":"","plannedSets":3,"proTips":["Lie on your back with your legs extended.","Bend your right knee and place your right ankle on your left thigh, just above the knee.","Grasp your left thigh with both hands and gently pull it towards your chest.","Hold the stretch for 20-30 seconds.","Release and repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"98FF4DAA-ACBA-5A1B-B825-2EC0B7E48E12","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('A956FFFD-BC9E-5009-91CD-06ABF6C345A1'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"A956FFFD-BC9E-5009-91CD-06ABF6C345A1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings"],"name":"Assisted Lying Gluteus And Piriformis Stretch","notes":"","plannedSets":3,"proTips":["Lie on your back with your legs extended.","Bend your right knee and place your right ankle on your left thigh, just above the knee.","Grasp your left thigh with both hands and gently pull it towards your chest.","Hold the stretch for 20-30 seconds.","Release the stretch and repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"5FAAB29B-6396-50EC-ADE6-9C8BC60D6928","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('2C7A6108-9305-541F-848D-F3CC912D26A1'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"2C7A6108-9305-541F-848D-F3CC912D26A1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Obliques"],"name":"Assisted Lying Leg Raise With Lateral Throw Down","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs extended and your arms by your sides.","Place your hands under your glutes for support.","Engage your abs and lift your legs off the ground, keeping them straight.","While keeping your legs together, lower them to one side until they are a few inches above the ground.","Pause for a moment, then lift your legs back to the starting position.","Repeat the movement to the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"53C4EABC-E4BC-5A85-B0C9-D0788890AE67","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"A1B6FE6F-67AA-5223-BC82-EE6926FBA491","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('37564866-AC7B-53B1-AEF1-B6DD5F3795A7'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"37564866-AC7B-53B1-AEF1-B6DD5F3795A7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Quadriceps"],"name":"Assisted Lying Leg Raise With Throw Down","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs extended and your arms by your sides.","Place your hands under your glutes for support.","Engage your core and lift your legs off the ground, keeping them straight.","Raise your legs until they are perpendicular to the ground.","Lower your legs back down to the starting position.","Simultaneously, throw your legs down towards the ground, keeping them straight.","Raise your legs back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"5942858C-C6A5-55F3-9040-786665048A78","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"098DF4B2-8B99-557B-96C5-EDEC8EE9385F","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('43727960-50A3-5B14-A344-39D25E554C2E'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Medicine Ball","hint":"","id":"43727960-50A3-5B14-A344-39D25E554C2E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Assisted Motion Russian Twist","notes":"","plannedSets":3,"proTips":["Sit on the ground with your knees bent and feet flat on the floor.","Hold the medicine ball with both hands in front of your chest.","Lean back slightly, engaging your abs and keeping your back straight.","Slowly twist your torso to the right, bringing the medicine ball towards the right side of your body.","Pause for a moment, then twist your torso to the left, bringing the medicine ball towards the left side of your body.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AD58845D-5C83-56D7-ABFE-97AC97FF5A68","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B9DEB63B-B5E3-51F2-B5AC-CA408A39D552'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"B9DEB63B-B5E3-51F2-B5AC-CA408A39D552","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Assisted Parallel Close Grip Pull-Up","notes":"","plannedSets":3,"proTips":["Adjust the machine to your desired weight and height.","Place your hands on the parallel bars with a close grip, palms facing each other.","Hang from the bars with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the bars, keeping your elbows close to your body.","Continue pulling until your chin is above the bars.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"B11CBE88-4016-581D-963E-2BCB29C9EC9C","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"5DFC6BA6-F5AC-55CE-8F5A-3994C9A06C88","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D284DECA-1FA6-5688-B61F-1C2EF91E2964'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"D284DECA-1FA6-5688-B61F-1C2EF91E2964","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Lower Back"],"name":"Assisted Prone Hamstring","notes":"","plannedSets":3,"proTips":["Lie face down on a mat or bench with your legs fully extended.","Have a partner or use a resistance band to secure your ankles.","Engage your hamstrings and lift your legs towards your glutes, keeping your knees straight.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"067985F7-800E-532F-8D81-0535A2AAB9FE","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"DD1C912D-A7E4-531C-8928-438A8EA953AA","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('609545A4-3069-5166-A54A-CE2E434F37A4'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"609545A4-3069-5166-A54A-CE2E434F37A4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings","Glutes"],"name":"Assisted Prone Lying Quads Stretch","notes":"","plannedSets":3,"proTips":["Lie face down on the ground with your legs extended.","Bend your left knee and reach back with your left hand to grab your left foot or ankle.","Gently pull your left foot towards your glutes, feeling a stretch in your left quad.","Hold the stretch for 20-30 seconds, then release.","Repeat with your right leg."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"018704CE-608F-5DD9-A6A1-6D89EC023D1D","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('21A6729B-5ED0-538E-A9EA-0C5BA1E2E494'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"21A6729B-5ED0-538E-A9EA-0C5BA1E2E494","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Quadriceps"],"name":"Assisted Prone Rectus Femoris Stretch","notes":"","plannedSets":3,"proTips":["Lie face down on the ground with your legs straight.","Bend your right knee and reach back with your right hand to grab your right foot or ankle.","Gently pull your right foot or ankle towards your glutes, feeling a stretch in the front of your right thigh.","Hold the stretch for 20-30 seconds.","Release and repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"BD7F6DBF-D3C3-53F2-B850-DCC404804BB5","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('01A26CFF-FE2A-512A-BBA2-8ACEAD56C03D'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"01A26CFF-FE2A-512A-BBA2-8ACEAD56C03D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Assisted Pull-Up","notes":"","plannedSets":3,"proTips":["Adjust the machine to your desired weight and height settings.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Hang with your arms fully extended and your feet off the ground.","Engage your back muscles and pull your body up towards the handles, keeping your elbows close to your body.","Continue pulling until your chin is above the handles.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"763FC46C-9C89-5417-BA08-64B4A8E28864","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"3DAE4341-0969-50FE-AA00-82BD152DC493","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4FA54C3E-5133-5056-98FF-AF8573154217'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"4FA54C3E-5133-5056-98FF-AF8573154217","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Assisted Seated Pectoralis Major Stretch With Stability Ball","notes":"","plannedSets":3,"proTips":["Sit on a stability ball with your feet flat on the ground and your back straight.","Hold a stability ball with both hands and extend your arms straight out in front of you.","Slowly lower the stability ball towards your chest, feeling a stretch in your pectoral muscles.","Hold the stretch for a few seconds, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"7FF69134-4352-5C4E-A0BC-ABC064691BE2","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('D320CC2A-3A23-59FC-BBA7-EA5EA3F37057'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"D320CC2A-3A23-59FC-BBA7-EA5EA3F37057","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Adductors","Hamstrings","Glutes"],"name":"Assisted Side Lying Adductor Stretch","notes":"","plannedSets":3,"proTips":["Lie on your side with your legs straight and stacked on top of each other.","Bend your bottom leg slightly for stability.","Place your top foot on a stable surface, such as a bench or step.","Keeping your top leg straight, slowly lower it towards the ground, feeling a stretch in your inner thigh.","Hold the stretch for 20-30 seconds.","Return to the starting position and repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"D3453669-93E5-51FB-A0D7-5EB50A60219D","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('31D4A3FE-4544-5F2E-8E08-EC1F65636041'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"31D4A3FE-4544-5F2E-8E08-EC1F65636041","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Assisted Sit-Up","notes":"","plannedSets":3,"proTips":["Sit on the edge of a bench or have someone hold your feet down.","Lie flat on your back with your knees bent and feet flat on the ground.","Place your hands behind your head with your elbows pointing outwards.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"B91E6E66-8901-59DD-902F-65C2E657C3D7","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"E9CAF2E4-53C2-5F25-BE90-926C3C3753BF","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('907206D2-D0D0-5E27-AB65-37D533D0E5DF'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"907206D2-D0D0-5E27-AB65-37D533D0E5DF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Assisted Standing Chin-Up","notes":"","plannedSets":3,"proTips":["Adjust the machine to your desired assistance level.","Stand on the foot platform and grip the handles with an overhand grip, slightly wider than shoulder-width apart.","Keep your chest up and shoulders back, engage your core, and slightly bend your knees.","Pull your body up by flexing your elbows and driving your elbows down towards your sides.","Continue pulling until your chin is above the bar.","Pause for a moment at the top, then slowly lower your body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"866D7623-FC23-5EA2-A3F8-EF7A24984031","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"7C699372-7E2C-510B-8436-6AF258198F86","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B933C009-369E-5127-B91B-D976B5F2213C'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Machine","hint":"","id":"B933C009-369E-5127-B91B-D976B5F2213C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Assisted Standing Pull-Up","notes":"","plannedSets":3,"proTips":["Adjust the machine to your desired weight and height settings.","Stand facing the machine with your feet shoulder-width apart.","Grasp the handles with an overhand grip, slightly wider than shoulder-width apart.","Engage your lats and biceps, and pull yourself up towards the handles.","Pause for a moment at the top, squeezing your back muscles.","Slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"7FA7AAB3-4FC9-54FD-A69A-4A4BACAC4550","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"64ECEA45-1BE9-5617-8264-366C077E5A15","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CC0B861E-F33F-5DCC-97D9-D9DB5B78B510'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"CC0B861E-F33F-5DCC-97D9-D9DB5B78B510","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Assisted Standing Triceps Extension (With Towel)","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a towel with both hands behind your head.","Keep your elbows close to your ears and your upper arms stationary.","Slowly extend your forearms upward, squeezing your triceps at the top.","Pause for a moment, then slowly lower the towel back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"2FE267AC-07EB-59CD-B742-4D0ABAC3845A","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"DAA4680E-3EFA-5E1D-A9C0-A1BB7982D55A","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5738F231-359F-5B41-8B4A-6B3D296192BF'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Machine","hint":"","id":"5738F231-359F-5B41-8B4A-6B3D296192BF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Assisted Triceps Dip (Kneeling)","notes":"","plannedSets":3,"proTips":["Adjust the machine to your desired weight and height.","Kneel down on the pad facing the machine, with your hands gripping the handles.","Lower your body by bending your elbows, keeping your back straight and close to the machine.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"245B7E4F-0A45-54ED-AD81-E0E5F692BD2C","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"2069C0DA-B5B9-506D-AF7A-A53D3544DEEF","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1AC44252-3C95-5558-8D0C-64E8B8434547'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Machine","hint":"","id":"1AC44252-3C95-5558-8D0C-64E8B8434547","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Assisted Wide-Grip Chest Dip (Kneeling)","notes":"","plannedSets":3,"proTips":["Adjust the machine to your desired height and secure your knees on the pad.","Grasp the handles with a wide grip and keep your elbows slightly bent.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Push yourself back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Set the pin and confirm the seat and pad positions.","id":"39AC52D2-5594-5291-9C8A-3A0684602648","intensity":"50% Target Weight","reps":12,"set":1},{"description":"One ramp set at working tempo.","id":"80E8AB7F-DC8C-5F34-9DA1-A880A4A09198","intensity":"75% Target Weight","reps":6,"set":2}],"type":"2-Set Standard Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0E1BA95E-35A0-5E65-BE33-DA9F1EC5E05F'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"0E1BA95E-35A0-5E65-BE33-DA9F1EC5E05F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Calves"],"name":"Astride Jumps","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Bend your knees and lower your body into a squat position.","Jump explosively upwards, extending your legs and arms.","While in the air, spread your legs apart and bring your arms out to the sides.","Land softly with your feet shoulder-width apart, bending your knees to absorb the impact.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('D7D2E3EC-9C2C-558D-BC36-536925A00604'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D7D2E3EC-9C2C-558D-BC36-536925A00604","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Quadriceps","Hamstrings","Glutes","Calves"],"name":"Back And Forth Step","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Step forward with your right foot, bending your knee and lowering your body into a lunge position.","Push off with your right foot and step back to the starting position.","Repeat the movement with your left foot, alternating legs with each step.","Continue stepping back and forth, maintaining a steady pace.","Repeat for the desired duration or number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('0C6043CD-1D33-522C-A049-D55956AA0EEF'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Stability Ball","hint":"","id":"0C6043CD-1D33-522C-A049-D55956AA0EEF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Glutes","Hamstrings"],"name":"Back Extension On Exercise Ball","notes":"","plannedSets":3,"proTips":["Place the stability ball on the ground and lie face down on top of it, with your hips resting on the ball and your feet against a wall or other stable surface.","Position your hands behind your head or crossed over your chest.","Engage your core and slowly lift your upper body off the ball, extending your back until your body forms a straight line from your head to your heels.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D988AB38-49A2-5C72-9D59-29BA824DEB86","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E51B3F16-2BC9-5739-8DEE-E33A4FC813A2'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"E51B3F16-2BC9-5739-8DEE-E33A4FC813A2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms","Core"],"name":"Back Lever","notes":"","plannedSets":3,"proTips":["Start by hanging from a pull-up bar with an overhand grip, hands slightly wider than shoulder-width apart.","Engage your core and pull your shoulder blades down and back.","Bend your knees and tuck them towards your chest.","Slowly lift your legs up, keeping them straight, until your body is parallel to the ground.","Hold this position for a few seconds, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"582F1D67-D451-5EC9-A760-6A568CB2AAAC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('281241D9-6FF0-5F60-B093-8FFAB1176CD7'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"281241D9-6FF0-5F60-B093-8FFAB1176CD7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Shoulders","Chest"],"name":"Back Pec Stretch","notes":"","plannedSets":3,"proTips":["Stand tall with your feet shoulder-width apart.","Extend your arms straight out in front of you, parallel to the ground.","Cross your arms in front of your body, with your right arm over your left arm.","Interlock your fingers and rotate your palms away from your body.","Slowly raise your arms up and away from your body, feeling a stretch in your back and chest.","Hold the stretch for 15-30 seconds, then release.","Repeat on the opposite side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"4684F388-FDF0-53BC-9160-0052B0F95CB7","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('D3398938-0C22-546D-A865-D92576B508C9'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"D3398938-0C22-546D-A865-D92576B508C9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings","Glutes","Calves"],"name":"Backward Jump","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Bend your knees slightly and jump backwards, pushing off with both feet.","Land softly on the balls of your feet, bending your knees to absorb the impact.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"751BC1D0-34E0-55BE-87DF-E82720D721F3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B466E84E-78BA-5BC1-BDBB-7D51AB8B531D'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B466E84E-78BA-5BC1-BDBB-7D51AB8B531D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Calves","Hamstrings","Glutes"],"name":"Balance Board","notes":"","plannedSets":3,"proTips":["Place the balance board on a flat surface.","Step onto the balance board with one foot, ensuring it is centered.","Slowly shift your weight onto the foot on the balance board, keeping your core engaged.","Maintain your balance and stability as you hold the position for a desired amount of time.","Repeat the exercise with the other foot."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"11ED30B2-DBB9-57F4-9349-21BB8E2107F3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E25483DE-438D-5A63-AF9F-C52FCB942885'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Band","hint":"","id":"E25483DE-438D-5A63-AF9F-C52FCB942885","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Band Alternating Biceps Curl","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the band with an underhand grip, palms facing up.","Keep your elbows close to your sides and slowly curl one arm up towards your shoulder, squeezing your biceps at the top.","Lower the arm back down to the starting position and repeat with the other arm.","Continue alternating arms for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"045F62CE-B2B5-530E-A7B8-813C4A1A0CA1","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('89B58F55-965E-5087-BAAC-97A5AC97F9E4'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"89B58F55-965E-5087-BAAC-97A5AC97F9E4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Band Alternating V-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs straight and your arms extended overhead, holding the band.","Engage your abs and lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes.","As you lower your legs and upper body back down, switch the position of your legs, crossing one over the other.","Repeat the movement, alternating the position of your legs with each repetition.","Continue for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"2E130B21-8BA8-5B6F-959F-613B00B12AF9","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A710A20B-0C2F-553B-8E70-93671054990F'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Band","hint":"","id":"A710A20B-0C2F-553B-8E70-93671054990F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Band Assisted Pull-Up","notes":"","plannedSets":3,"proTips":["Attach the band to a pull-up bar or sturdy anchor point.","Step onto the band and grip the bar with your palms facing away from you, hands slightly wider than shoulder-width apart.","Hang with your arms fully extended, keeping your core engaged and your shoulders down and back.","Pull your body up towards the bar by squeezing your shoulder blades together and driving your elbows down towards your hips.","Continue pulling until your chin is above the bar, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"C5CB2C3E-0520-5C8F-A49C-B57ACAB453EB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E41D1604-442B-5A95-AD9A-AAB194E0DBEA'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"E41D1604-442B-5A95-AD9A-AAB194E0DBEA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Lower Back"],"name":"Band Assisted Wheel Rollerout","notes":"","plannedSets":3,"proTips":["Kneel on the floor and hold the handles of the band with both hands, palms facing down.","Place the band on the ground in front of you and position your hands shoulder-width apart.","Engage your core and slowly roll the wheel forward, extending your body as far as you can while maintaining control.","Pause for a moment at the furthest point, then slowly roll the wheel back towards your knees to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"99F55C2F-A62E-56D5-97A5-E78DF851FBA6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F13C8CEC-BAD1-5184-BE5C-6A6F01D76A5F'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Band","hint":"","id":"F13C8CEC-BAD1-5184-BE5C-6A6F01D76A5F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Band Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the band handles with an overhand grip, slightly wider than shoulder-width apart.","Extend your arms fully, pushing the bands away from your chest.","Slowly lower the bands back down to your chest, keeping your elbows at a 90-degree angle.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"52F0CCFF-371F-5F2A-BC5F-64E90C1FF3BE","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('993343B3-5012-5A38-B983-A4D35DDD0E36'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Band","hint":"","id":"993343B3-5012-5A38-B983-A4D35DDD0E36","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Band Bent-Over Hip Extension","notes":"","plannedSets":3,"proTips":["Attach the band to a sturdy anchor point at ankle height.","Stand facing away from the anchor point with your feet shoulder-width apart.","Step back to create tension in the band, keeping your knees slightly bent.","Hinge at the hips and lean forward, maintaining a neutral spine.","Extend your right leg straight back, squeezing your glutes at the top.","Lower your right leg back down and repeat with the left leg.","Continue alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9B807F97-24DC-598D-8643-21E58699C54C","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BD40F0C6-8347-599F-B707-379D81E7F656'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"BD40F0C6-8347-599F-B707-379D81E7F656","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors","Obliques"],"name":"Band Bicycle Crunch","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your hands behind your head and your knees bent.","Lift your feet off the ground and bring your right knee towards your chest while simultaneously twisting your torso to bring your left elbow towards your right knee.","Straighten your right leg while bringing your left knee towards your chest and twisting your torso to bring your right elbow towards your left knee.","Continue alternating the twisting motion, as if you are pedaling a bicycle, while keeping your core engaged throughout the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FDAFDB9E-BA84-55C4-9480-D31BF02F7FA0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('147531D4-E139-5C1B-BE0A-4E0F78F96505'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Band","hint":"","id":"147531D4-E139-5C1B-BE0A-4E0F78F96505","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Band Close-Grip Pulldown","notes":"","plannedSets":3,"proTips":["Attach the band to a high anchor point, such as a pull-up bar or sturdy beam.","Stand facing the anchor point and grab the band with an underhand grip, hands shoulder-width apart.","Step back to create tension in the band, keeping your feet hip-width apart.","Engage your core and keep your back straight as you pull the band down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the band back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"CA06E9A9-8B92-5A3B-89B5-5441E0EE4E65","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B8C7C9CE-F1AF-5575-81AB-E7E7A5CC3F28'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Band","hint":"","id":"B8C7C9CE-F1AF-5575-81AB-E7E7A5CC3F28","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Band Close-Grip Push-Up","notes":"","plannedSets":3,"proTips":["Place a band around your upper arms, just above the elbows.","Assume a push-up position with your hands directly under your shoulders and your body in a straight line from head to heels.","Bend your elbows and lower your chest towards the ground, keeping your elbows close to your sides.","Push through your palms to extend your arms and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4B16BEC9-4BC6-591C-AA28-9A006DC33AD2","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('493885BF-4F2D-5A88-A5A5-FD87A78FFE31'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Band","hint":"","id":"493885BF-4F2D-5A88-A5A5-FD87A78FFE31","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Band Concentration Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your legs spread apart and your feet flat on the ground.","Hold one end of the band in your hand and step on the other end with your foot on the same side.","Lean forward slightly and rest your elbow on the inside of your thigh, just above the knee.","With your palm facing up, slowly curl your hand towards your shoulder, keeping your upper arm stationary.","Pause for a moment at the top, then slowly lower your hand back down to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"44B9465C-6319-5660-8BCA-BD6B2CE2C5D4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D46BB9E2-966D-5C11-8230-F6FEAC0E3908'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Band","hint":"","id":"D46BB9E2-966D-5C11-8230-F6FEAC0E3908","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Band Fixed Back Close Grip Pulldown","notes":"","plannedSets":3,"proTips":["Attach the band to a fixed point above you, such as a pull-up bar or sturdy beam.","Sit down on a bench or chair facing the band, with your feet flat on the ground and your knees bent.","Grasp the band with a close grip, palms facing towards you.","Keep your back straight and engage your core.","Pull the band down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, feeling the contraction in your lats.","Slowly release the band back to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"16520E03-AE4E-557D-BE12-1FCE9BE609C4","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0852E404-1D71-5937-80E8-351EA0C94223'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Band","hint":"","id":"0852E404-1D71-5937-80E8-351EA0C94223","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids","Rear Deltoids"],"name":"Band Fixed Back Underhand Pulldown","notes":"","plannedSets":3,"proTips":["Attach the band to a sturdy anchor point above your head.","Stand facing the anchor point with your feet shoulder-width apart.","Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart.","Step back to create tension in the band, keeping your arms fully extended.","Engage your core and squeeze your shoulder blades together.","Pull the band down towards your chest, leading with your elbows.","Pause for a moment at the bottom of the movement, feeling the contraction in your lats.","Slowly release the tension in the band and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0546D212-50E9-543D-AFB7-303821807EAC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('80E6A7E2-AC1D-5142-ACFD-564789AECE3C'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Band","hint":"","id":"80E6A7E2-AC1D-5142-ACFD-564789AECE3C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Upper Back"],"name":"Band Front Lateral Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down.","Keep your arms straight and lift the band up in front of you until your arms are parallel to the ground.","Pause for a moment at the top, then slowly lower the band back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5FAC63EE-C828-531F-9431-07E807CA2E4A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('86506FBC-A1E2-57D9-9444-4D4148B2E2CE'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Band","hint":"","id":"86506FBC-A1E2-57D9-9444-4D4148B2E2CE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Band Front Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing down.","Keep your arms straight and slowly raise them forward until they are parallel to the ground.","Pause for a moment at the top, then slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"9F564A8F-5884-5505-9758-0E6BFBF0F071","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7CAB1D4F-354A-5714-A7DD-F1CE5EF68D92'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Band","hint":"","id":"7CAB1D4F-354A-5714-A7DD-F1CE5EF68D92","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Band Hip Lift","notes":"","plannedSets":3,"proTips":["Lie on your back with your knees bent and feet flat on the ground.","Place a resistance band just above your knees.","Engage your glutes and core muscles.","Press your heels into the ground and lift your hips off the floor, squeezing your glutes at the top.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8B84AD83-48C3-5677-A703-C8AD0162ABC8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('95CD589D-F264-5C90-B03F-66C8BD96181E'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"95CD589D-F264-5C90-B03F-66C8BD96181E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Glutes"],"name":"Band Horizontal Pallof Press","notes":"","plannedSets":3,"proTips":["Attach the band to a sturdy anchor point at waist height.","Stand perpendicular to the anchor point with your feet shoulder-width apart.","Grasp the band handle with both hands and step away from the anchor point to create tension in the band.","Bring your hands to your chest, keeping your elbows bent and close to your body.","Engage your core and maintain a stable stance.","Extend your arms straight out in front of you, pushing the band away from your body.","Hold the extended position for a few seconds, focusing on maintaining tension in your core.","Slowly bring your hands back to your chest, resisting the pull of the band.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"11DE8847-264B-5BA2-B746-F2ED97505ECB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A3470734-29BA-54CB-A71D-BC1B5C0D9215'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"A3470734-29BA-54CB-A71D-BC1B5C0D9215","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Band Jack Knife Sit-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs straight and your arms extended overhead, holding the band.","Engage your abs and lift your legs and upper body simultaneously, bringing your hands towards your feet.","Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E24597C6-8E27-58D1-B714-402AA09365FA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('342BBFF3-8988-5F91-B0FA-1483057379F7'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Band","hint":"","id":"342BBFF3-8988-5F91-B0FA-1483057379F7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Rhomboids"],"name":"Band Kneeling One Arm Pulldown","notes":"","plannedSets":3,"proTips":["Attach the band to a sturdy anchor point above your head.","Kneel down and hold the band with one hand, palm facing down.","Extend your arm fully overhead, keeping your elbow slightly bent.","Engage your lat muscles and pull the band down towards your side, bringing your elbow towards your ribcage.","Pause for a moment at the bottom, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"E543357C-417D-5234-AB1B-9B503408ACE8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E7B9D9DD-686D-5B49-9DAF-6EC50BDF2E45'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"E7B9D9DD-686D-5B49-9DAF-6EC50BDF2E45","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Band Kneeling Twisting Crunch","notes":"","plannedSets":3,"proTips":["Attach the band to a sturdy anchor point at waist height.","Kneel down facing away from the anchor point and hold the band with both hands, keeping your elbows bent and close to your sides.","Engage your abs and slowly twist your torso to one side, bringing your hands towards your opposite hip.","Pause for a moment, then slowly return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"7CA3C67C-196D-5A4F-BC5C-BA82E7A4C145","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4D212236-D3F8-587F-AD15-6AD8111CBDDB'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Band","hint":"","id":"4D212236-D3F8-587F-AD15-6AD8111CBDDB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Band Lying Hip Internal Rotation","notes":"","plannedSets":3,"proTips":["Lie on your back with your legs straight and a resistance band looped around your feet.","Bend your knees and bring them towards your chest, keeping your feet together.","Slowly rotate your knees outwards, away from each other, while keeping your feet together.","Pause for a moment at the end of the rotation, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"E11B353B-0D0B-5EF3-A3B2-60F49D9EF038","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('76589D93-8125-5628-A7DC-261980BE78A9'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"76589D93-8125-5628-A7DC-261980BE78A9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Band Lying Straight Leg Raise","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs straight and your feet together.","Place the band around the arches of your feet and hold the ends of the band with your hands.","Engaging your abs, lift both legs off the ground until they are perpendicular to the floor.","Pause for a moment at the top, then slowly lower your legs back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"00ADB873-E9B5-5D1F-BB62-40D5F25692FA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1668607D-DDB6-5236-8A95-91E87E99AA0A'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Band","hint":"","id":"1668607D-DDB6-5236-8A95-91E87E99AA0A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Band One Arm Overhead Biceps Curl","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and place one end of the band under your foot.","Hold the other end of the band with your arm fully extended overhead, palm facing forward.","Keeping your upper arm stationary, curl your forearm towards your shoulder, squeezing your biceps.","Pause for a moment at the top, then slowly lower your forearm back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"6FFB048A-0AD9-5118-B30E-322F274D1F98","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CE4F1003-0A71-5EB1-92AE-7074B4740660'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Band","hint":"","id":"CE4F1003-0A71-5EB1-92AE-7074B4740660","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings"],"name":"Band One Arm Single Leg Split Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart and place a resistance band around your ankles.","Extend one leg forward and rest the top of your foot on a bench or step behind you.","Hold onto a support with one hand for balance.","Bend your standing leg and lower your body down into a squat position, keeping your knee in line with your toes.","Push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"DF77C8D1-3508-59F8-886E-70E643160A41","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0CA72507-CFD8-53ED-A029-B2D695C0B0A2'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Band","hint":"","id":"0CA72507-CFD8-53ED-A029-B2D695C0B0A2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Band One Arm Standing Low Row","notes":"","plannedSets":3,"proTips":["Attach the band to a stable anchor point at waist height.","Stand facing the anchor point with your feet shoulder-width apart.","Hold the band with one hand, palm facing inward, and step back to create tension in the band.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Pull the band towards your waist, squeezing your shoulder blades together.","Pause for a moment at the top of the movement, then slowly release the band back to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"A5AA9319-C441-59CA-8CF0-65742B63B2B6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4A8A2177-501E-5FD0-9803-5174C2A75360'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Band","hint":"","id":"4A8A2177-501E-5FD0-9803-5174C2A75360","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Band One Arm Twisting Chest Press","notes":"","plannedSets":3,"proTips":["Attach the band to a sturdy anchor point at chest height.","Stand with your side facing the anchor point and grab the band with one hand.","Step away from the anchor point to create tension in the band.","Position your feet shoulder-width apart and slightly bend your knees.","Bring your hand holding the band across your body, towards the opposite shoulder.","While maintaining tension in the band, push your hand forward and away from your body, extending your arm.","Slowly return to the starting position and repeat for the desired number of repetitions.","Switch sides and repeat the exercise with the other hand."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"22C587D2-27F5-5182-866C-9648886E9BFA","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('43CC0856-70AA-588D-9BBB-C2F266678656'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Band","hint":"","id":"43CC0856-70AA-588D-9BBB-C2F266678656","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Shoulders"],"name":"Band One Arm Twisting Seated Row","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your feet flat on the ground and your back straight.","Hold the band with one hand and extend your arm fully in front of you.","Keeping your back straight, pull the band towards your body by bending your elbow and squeezing your shoulder blades together.","At the same time, twist your torso towards the side of the pulling arm.","Pause for a moment at the top, then slowly release the tension in the band and return to the starting position.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"D4B9C4E8-82BA-5B1A-9A6A-B7244FDECC09","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CE0062DD-947D-5B7C-8753-10F281F47BA0'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Band","hint":"","id":"CE0062DD-947D-5B7C-8753-10F281F47BA0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Band Pull Through","notes":"","plannedSets":3,"proTips":["Attach a resistance band to a sturdy anchor point at ground level.","Stand facing away from the anchor point with your feet shoulder-width apart.","Step forward to create tension in the band, keeping your knees slightly bent.","Hinge at the hips and push your glutes back, maintaining a slight bend in your knees.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Drive your hips forward and squeeze your glutes to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"444AB222-7749-54FB-AE84-B547EA871D04","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('179C318F-BE76-5C91-B11E-0374790B2E41'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"179C318F-BE76-5C91-B11E-0374790B2E41","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Chest"],"name":"Band Push Sit-Up","notes":"","plannedSets":3,"proTips":["Attach the band securely to a stable anchor point.","Lie flat on your back with your knees bent and feet flat on the ground.","Hold the band with both hands and extend your arms straight up towards the ceiling.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"76F8C130-557F-5641-81F6-C5D5FE42A2D6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0B1719E6-E202-5632-9CA3-1594AABC0721'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Band","hint":"","id":"0B1719E6-E202-5632-9CA3-1594AABC0721","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Upper Back","Trapezius"],"name":"Band Reverse Fly","notes":"","plannedSets":3,"proTips":["Attach the band to a stationary object at chest height.","Stand with your feet shoulder-width apart and hold the band with both hands in front of you.","Keep your arms straight and lift them out to the sides until they are parallel to the ground.","Squeeze your shoulder blades together at the top of the movement.","Slowly lower your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"57199155-A9D8-56F9-908B-98AB18877B73","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('49AE41B2-FEBC-537C-8A33-BEC29F4C3844'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Band","hint":"","id":"49AE41B2-FEBC-537C-8A33-BEC29F4C3844","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms"],"name":"Band Reverse Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your feet flat on the ground.","Hold the band with an overhand grip, palms facing down, and wrap it around your fingers.","Rest your forearms on your thighs, with your wrists hanging off the edge.","Slowly curl your wrists upward, squeezing your forearms.","Pause for a moment at the top, then slowly lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"AA2F4987-E03F-5401-A00B-BD639768BEF6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('8C5F6D9B-F06C-5161-87CC-056B2B1CD39B'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Band","hint":"","id":"8C5F6D9B-F06C-5161-87CC-056B2B1CD39B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Band Seated Hip Internal Rotation","notes":"","plannedSets":3,"proTips":["Sit on a chair or bench with your back straight and feet flat on the ground.","Place a resistance band around your thighs, just above your knees.","Keep your knees bent at a 90-degree angle and your feet shoulder-width apart.","Engage your glutes and slowly rotate your knees outward, pushing against the resistance of the band.","Pause for a moment at the end of the movement, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"32738EA9-6B55-5AA2-A059-38DC3A30CD86","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('31CAA5D4-C5AB-5337-94D7-774812625244'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"31CAA5D4-C5AB-5337-94D7-774812625244","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Band Seated Twist","notes":"","plannedSets":3,"proTips":["Sit on the ground with your legs extended in front of you and your back straight.","Wrap the band around your waist and hold the ends with both hands.","Engage your abs and slowly twist your torso to one side, keeping your back straight and your feet on the ground.","Pause for a moment at the end of the twist, then slowly return to the starting position.","Repeat the twist to the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"394EA502-9AF8-5F69-B32A-3847EB469AF7","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('53C6B845-FF89-560B-AF96-DDCC565ECAEC'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Band","hint":"","id":"53C6B845-FF89-560B-AF96-DDCC565ECAEC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Band Shoulder Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and place the band under your feet.","Hold the band with your palms facing forward and raise your hands to shoulder height, elbows bent.","Press the band overhead, fully extending your arms.","Pause for a moment at the top, then slowly lower the band back to shoulder height.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"56E5035B-378D-57D4-AC21-8C8B8246B090","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C47395D5-643A-59D4-BEDE-35ECDE36A1CA'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Band","hint":"","id":"C47395D5-643A-59D4-BEDE-35ECDE36A1CA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders"],"name":"Band Shrug","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and place the band under your feet, holding the ends with your hands.","Keep your arms straight and relaxed, and let the band hang in front of your thighs.","Engage your traps by shrugging your shoulders upward, lifting the band as high as possible.","Hold the contraction for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5B56150E-D4C5-51AC-89E5-C9F995B37358","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('23BB4CFD-E948-5DDB-9DFD-3435EFEA2588'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Band","hint":"","id":"23BB4CFD-E948-5DDB-9DFD-3435EFEA2588","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Band Side Triceps Extension","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the band with both hands, palms facing down.","Extend your arms straight out to the sides, keeping them parallel to the ground.","Slowly bend your elbows and bring your hands towards your shoulders, keeping your upper arms still.","Pause for a moment, then slowly extend your arms back out to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"0532E76E-A06F-5E68-A12E-CF82AF820E78","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1617F150-73EE-5269-8A86-9083A675CD59'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Band","hint":"","id":"1617F150-73EE-5269-8A86-9083A675CD59","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Ankles","Feet"],"name":"Band Single Leg Calf Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart and place the band around the ball of your left foot.","Hold onto a stable object for balance if needed.","Slowly raise your left heel off the ground, lifting your body weight onto the ball of your foot.","Pause for a moment at the top, then slowly lower your left heel back down to the starting position.","Repeat for the desired number of repetitions, then switch to the right leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8B59EEA1-16BA-5F8E-9CA8-F04EBD23D1AC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('17756D60-D2AD-5058-BA00-B896EC8B330D'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Band","hint":"","id":"17756D60-D2AD-5058-BA00-B896EC8B330D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Band Single Leg Reverse Calf Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart and place the band around the ball of your foot.","Hold onto a stable object for balance.","Slowly raise your heel off the ground, lifting your body weight onto the ball of your foot.","Pause for a moment at the top, then slowly lower your heel back down to the starting position.","Repeat for the desired number of repetitions, then switch to the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"08C79517-51E3-5C0E-B861-D879887EED7B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('02BCF035-7925-5B92-8BCE-0DC6C31098DD'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Band","hint":"","id":"02BCF035-7925-5B92-8BCE-0DC6C31098DD","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings"],"name":"Band Single Leg Split Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart and place a resistance band around your ankles.","Take a big step forward with your right foot and a smaller step back with your left foot.","Bend your knees and lower your body until your right thigh is parallel to the ground, keeping your left knee slightly above the ground.","Push through your right heel to return to the starting position.","Repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"83165403-AE58-5EB5-BE7B-B9BAF5C20259","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('23EF0382-F252-5AC5-9935-8DAD923C3925'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Band","hint":"","id":"23EF0382-F252-5AC5-9935-8DAD923C3925","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Band Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, with the band placed just above your knees.","Keeping your chest up and core engaged, push your hips back and bend your knees to lower into a squat position.","Make sure your knees are tracking over your toes and your weight is in your heels.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"336C54CA-C08A-5A8A-A9C0-FAA59EA6E1DD","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2681BD8E-425B-5CE4-962E-FBBDE7EE489F'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Band","hint":"","id":"2681BD8E-425B-5CE4-962E-FBBDE7EE489F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Back"],"name":"Band Squat Row","notes":"","plannedSets":3,"proTips":["Attach the band to a sturdy anchor point at waist height.","Stand facing the anchor point with your feet shoulder-width apart.","Hold the band handles with your palms facing each other and your arms extended in front of you.","Bend your knees and lower into a squat position, keeping your back straight and chest lifted.","From the squat position, pull the band handles towards your body, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1A598D4D-CB64-58CC-AD38-26F3B10A636D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2790A1AB-519B-531F-A463-604BF958ADCB'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"2790A1AB-519B-531F-A463-604BF958ADCB","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Band Standing Crunch","notes":"","plannedSets":3,"proTips":["Attach the band to a sturdy anchor point at waist height.","Stand facing away from the anchor point with your feet shoulder-width apart.","Hold the band with both hands and bring it up to your chest, keeping your elbows bent and close to your body.","Engage your abs and slowly crunch forward, bringing your chest towards your knees.","Pause for a moment at the top of the crunch, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F87D7F81-3F9A-5D8D-B56E-35EBBF6F6073","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C88BAA6E-26C5-5877-BFDA-61F4901608B9'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Band","hint":"","id":"C88BAA6E-26C5-5877-BFDA-61F4901608B9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids","Biceps"],"name":"Band Standing Rear Delt Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and place the band under your feet.","Hold the band handles with your palms facing each other and your arms extended in front of you.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Pull the band towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"F573A3D2-5EC4-5EA3-9483-71BF2AFD930A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('21E0D813-BB5F-5B3E-A375-A632E2CFAA92'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"21E0D813-BB5F-5B3E-A375-A632E2CFAA92","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques"],"name":"Band Standing Twisting Crunch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and place the band around your upper back, crossing it in front of your chest.","Hold the ends of the band with your hands, keeping your elbows bent and close to your sides.","Engage your abs and twist your torso to one side, bringing your elbow towards the opposite knee.","Pause for a moment, then return to the starting position.","Repeat on the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FE3A2D2F-B21E-5382-BA01-6E0C2D82016B","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('63BE160A-C768-559C-8480-17CB02ACBA5D'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Band","hint":"","id":"63BE160A-C768-559C-8480-17CB02ACBA5D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Band Step-Up","notes":"","plannedSets":3,"proTips":["Place a band around your thighs, just above your knees.","Stand facing a step or platform with your feet hip-width apart.","Step up onto the platform with your right foot, pushing through your heel.","Extend your left leg behind you, keeping it straight.","Lower your left foot back down to the ground.","Repeat with your left foot stepping up onto the platform.","Continue alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"37F78563-735C-579A-BFB2-CACD3010039A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0D1AB5B6-C5AB-5711-A1AA-763C396B88F7'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Band","hint":"","id":"0D1AB5B6-C5AB-5711-A1AA-763C396B88F7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Band Stiff Leg Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and place the band around your ankles.","Hold the band with both hands in front of your thighs, palms facing your body.","Keeping your back straight and your core engaged, hinge at the hips and slowly lower your upper body towards the ground.","As you lower, push your hips back and allow your knees to bend slightly.","Lower the band towards the ground, feeling a stretch in your hamstrings.","Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your upper body back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"83260A83-4CF6-59C2-8BA2-227D2A43BB00","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6BBDBE32-2530-5DCD-8F6C-4ECD0728BF56'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Band","hint":"","id":"6BBDBE32-2530-5DCD-8F6C-4ECD0728BF56","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Band Straight Back Stiff Leg Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and place the band around your upper legs.","Hold the band with both hands in front of your thighs, palms facing your body.","Keeping your back straight and your knees slightly bent, hinge at the hips and lower the band towards the ground.","Feel the stretch in your hamstrings as you lower the band.","Engage your glutes and hamstrings to lift your body back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"58211C93-2059-56BE-BCF1-EEA82E8EB2FC","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E4B4B4E7-47FC-5965-9E3B-8E70773FBD30'::uuid, '{"category":"Back","difficulty":"Advanced","equipment":"Band","hint":"","id":"E4B4B4E7-47FC-5965-9E3B-8E70773FBD30","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Spine","Hamstrings","Glutes"],"name":"Band Straight Leg Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and place the band around your feet.","Hold the band with both hands, palms facing your body, and keep your arms straight.","Engage your core and maintain a slight bend in your knees.","Slowly hinge forward at your hips, keeping your back straight and chest lifted.","Lower the band towards the ground while keeping your legs straight.","Pause for a moment at the bottom, then squeeze your glutes and hamstrings to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8AF27870-1D8E-5464-B98E-CAC4220B5516","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D8D28CBB-1314-59C3-9633-E22697E05D9F'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Band","hint":"","id":"D8D28CBB-1314-59C3-9633-E22697E05D9F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Band Twisting Overhead Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and place the band under your feet.","Hold the band handles at shoulder height with your palms facing forward.","Engage your core and press the band overhead, fully extending your arms.","As you press, twist your torso to one side, keeping your hips stable.","Pause for a moment at the top, then return to the starting position.","Repeat the press and twist on the opposite side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"610809AB-AF53-5BDE-A4F5-5EB14A410FB0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2998202F-F72B-5F3F-9D11-DA447BEB3075'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Band","hint":"","id":"2998202F-F72B-5F3F-9D11-DA447BEB3075","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Ankles","Feet"],"name":"Band Two Legs Calf Raise - (Band Under Both Legs) V. 2","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and place a resistance band under both feet.","Hold the ends of the band with your hands for stability.","Raise your heels off the ground as high as possible, using your calves.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"84786D1F-0B27-562C-8824-B38A8BB14AC3","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C2C9B41B-1C6A-5055-B60B-EBF06B6D50DA'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Band","hint":"","id":"C2C9B41B-1C6A-5055-B60B-EBF06B6D50DA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Band Underhand Pulldown","notes":"","plannedSets":3,"proTips":["Attach the band to a high anchor point, such as a pull-up bar or sturdy beam.","Stand facing the anchor point with your feet shoulder-width apart.","Grasp the band with an underhand grip, hands slightly wider than shoulder-width apart.","Extend your arms fully overhead, keeping your elbows slightly bent.","Engage your lats and pull the band down towards your chest, squeezing your shoulder blades together.","Pause for a moment at the bottom of the movement, then slowly release the tension and return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"54A371B0-FD0E-5477-A213-1AC0623A74FF","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('65AAE532-55FE-5B95-8740-D75007526527'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"65AAE532-55FE-5B95-8740-D75007526527","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Band V-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your legs straight and your arms extended overhead, holding the band.","Engaging your abs, lift your legs and upper body off the ground simultaneously, reaching your hands towards your toes.","Pause for a moment at the top, then slowly lower your legs and upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FE45B978-C4A4-58B4-A60B-D2D29C560BDB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9609B6F7-D33C-5A9C-8DDC-652A633765F3'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Band","hint":"","id":"9609B6F7-D33C-5A9C-8DDC-652A633765F3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Glutes"],"name":"Band Vertical Pallof Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and wrap the band around a sturdy object at chest height.","Hold the band with both hands and step away from the anchor point, creating tension in the band.","Position yourself perpendicular to the anchor point, with your side facing the band.","Extend your arms straight out in front of you, keeping your hands at chest height.","Engage your core and press the band away from your chest, fully extending your arms.","Hold the position for a few seconds, then slowly bring the band back towards your chest.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4F3A9CA8-2AAB-5404-9CD6-42401585D9A8","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('22E818AF-6217-5EA7-9EFB-A3C57D07DEE8'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Band","hint":"","id":"22E818AF-6217-5EA7-9EFB-A3C57D07DEE8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Triceps"],"name":"Band Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench or chair with your feet flat on the ground.","Hold the band with both hands, palms facing up, and rest your forearms on your thighs.","Slowly curl your wrists upward, squeezing your forearms.","Pause for a moment at the top, then slowly lower your wrists back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1F91D032-03AE-54E9-9B24-E296F03DABE6","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('49A56615-360B-59EF-BD3D-34E82EC1B2F1'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Band","hint":"","id":"49A56615-360B-59EF-BD3D-34E82EC1B2F1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Rhomboids"],"name":"Band Y-Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the band in front of your thighs with your palms facing inwards.","Keep your arms straight and lift them up and out to the sides, forming a ''Y'' shape with your body.","Squeeze your shoulder blades together at the top of the movement.","Slowly lower your arms back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"1E19B80A-CBF0-5597-826E-8D455732E93E","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D86EF2D8-971E-5F11-BE39-5D8E0C5C4BAA'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"D86EF2D8-971E-5F11-BE39-5D8E0C5C4BAA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Alternate Biceps Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a barbell in each hand, palms facing forward.","Keep your upper arms stationary and exhale as you curl the weights while contracting your biceps.","Continue to raise the barbells until your biceps are fully contracted and the barbells are at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly begin to lower the barbells back to the starting position.","Repeat for the desired number of repetitions, alternating arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"5C721BBF-5D13-5902-9EB3-A7D83A31D2B9","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"2CC0AAC9-101B-59DD-980F-156A0B1E25E2","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"286A9434-4EDC-5EB1-9470-F009AE54E392","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"2BB7289E-C2D9-5503-86EA-DE52BAA39FF3","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D42B5466-8AF2-5424-AE5B-C8310F3BA23E'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"D42B5466-8AF2-5424-AE5B-C8310F3BA23E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings","Glutes","Calves"],"name":"Barbell Bench Front Squat","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, just below your collarbone.","Hold the barbell with an overhand grip, keeping your elbows up and your upper arms parallel to the ground.","Lower your body down into a squat position by bending at the knees and hips, keeping your back straight and your chest up.","Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"701F33AB-827E-5095-9D94-1B95A3F5E6D1","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"789957D5-5355-5352-A090-01E581D6B4FA","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"35F0AA91-81F3-50EA-84AD-76D231B96C3A","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"68CACC2B-D71D-5D57-B08A-BC4AB5A2C8E8","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E64231C0-29A7-5E26-898D-E9BD180231E1'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"E64231C0-29A7-5E26-898D-E9BD180231E1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Barbell Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Lower the barbell slowly towards your chest, keeping your elbows tucked in.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"8C1E5617-0F3B-579A-BD57-018AA3F9D51C","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"E28B0E3F-CBC9-5830-A990-7FC0BB58F4BD","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"9588DDF7-11A1-5EC9-95C8-F89C709BAA3F","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"6AAC2E56-9564-57D0-9982-E8C04F5BD32B","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E062C535-E610-5FE9-87C6-EDD4AB7C48BF'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"E062C535-E610-5FE9-87C6-EDD4AB7C48BF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Barbell Bench Squat","notes":"","plannedSets":3,"proTips":["Set up a barbell on a squat rack at chest height.","Stand facing away from the rack, with your feet shoulder-width apart.","Bend your knees and lower your body down into a squat position, keeping your back straight and chest up.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and step back, ensuring your feet are still shoulder-width apart.","Lower your body down into a squat, keeping your knees in line with your toes.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"58283554-A188-571D-9795-3D81275D2C22","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"6BC3D176-0E79-5369-AE70-E4700B188D16","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"EFFD9F50-8400-5074-A0FC-0FFBD14AF5FD","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E6760D15-41D4-53D1-89A3-67E425A07F17","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2376C186-D7D2-5BB9-B51E-F73EB7AADC71'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"2376C186-D7D2-5BB9-B51E-F73EB7AADC71","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Triceps","Chest"],"name":"Barbell Bent Arm Pullover","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your head at one end and your feet on the floor.","Hold a barbell with a shoulder-width grip and extend your arms straight above your chest.","Lower the barbell behind your head while keeping your arms slightly bent.","Pause for a moment, then raise the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"4891106B-D6C2-541D-B0B2-ED8DA61F4750","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"313B58CF-DAD9-5997-AA7E-EDC5D973367A","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"70DCC437-B05C-5A6D-B36B-68179A82A451","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"48EBC5BB-163B-5BEA-AA03-431C2A539653","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('156E41F6-C778-5FF1-9025-FBA67D998B0F'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"156E41F6-C778-5FF1-9025-FBA67D998B0F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Barbell Bent Over Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Bend forward at the hips while keeping your back straight and chest up.","Grasp the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Pull the barbell towards your lower chest by retracting your shoulder blades and squeezing your back muscles.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"56668C54-E4F1-5C60-A57C-088E37FE9F98","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"C6AB9649-ED00-55A3-9436-2155C909ABFE","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"0F0BDA8C-EC66-588C-8905-3F3A4937A50F","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"8C96EE64-4CBF-5C72-9187-E9CB50B87877","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0E80C5E7-96B2-5E9F-9918-15173B19FF52'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"0E80C5E7-96B2-5E9F-9918-15173B19FF52","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Biceps Curl (With Arm Blaster)","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.","Place your upper arms against the arm blaster, keeping your elbows close to your torso.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"B99D6363-7548-594F-B0C7-D1F75E2E7D4D","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"BCF86821-B9CC-5C37-8BC2-11F57BD16214","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"C7B44955-C72B-5ED7-BF5E-1C8BD31DBD3F","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"C0DC648F-78D9-5056-985F-B0F17D86673E","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('07629A8D-72E7-5CF5-A88B-BA9AB82F216B'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"07629A8D-72E7-5CF5-A88B-BA9AB82F216B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Hamstrings","Glutes","Shoulders","Triceps"],"name":"Barbell Clean And Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and the barbell on the floor in front of you.","Bend your knees and hinge at the hips to lower down and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Drive through your heels and extend your hips and knees to lift the barbell off the floor, keeping it close to your body.","As the barbell reaches your thighs, explosively extend your hips, shrug your shoulders, and pull the barbell up towards your chest.","As the barbell reaches chest height, quickly drop under it and catch it at shoulder level, with your elbows pointing forward and your palms facing up.","From the catch position, press the barbell overhead by extending your arms and pushing the barbell straight up.","Lower the barbell back down to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"3A79A119-8D59-5832-A7F3-97E09A0EB26A","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"E06452F3-0CC4-549B-A2E9-35F44B0005A4","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"E283418E-58C2-5036-8EA0-6A47BE61A8C5","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"F885839C-FC91-57BF-951E-991C1B7849ED","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('35F34957-6FF1-54BF-9763-359506417EA7'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"35F34957-6FF1-54BF-9763-359506417EA7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves","Core"],"name":"Barbell Clean-Grip Front Squat","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart and the barbell resting on your upper chest, with your elbows pointing forward.","Lower your body by bending your knees and pushing your hips back, as if you are sitting back into a chair.","Keep your chest up and your back straight as you lower down, making sure your knees do not go past your toes.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"6DE0A7AE-E808-5CC6-9226-1DD612D8F6FD","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"F4B88720-AEBB-515C-944B-56386F72EB4A","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"196AE32F-BFE5-504D-A6D9-E5DCE7F1E327","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"6EE2FB71-0E57-5188-981D-5F1ACB19DC96","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E9D09CA6-CB53-5A0D-9208-B701034770A1'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"E9D09CA6-CB53-5A0D-9208-B701034770A1","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Barbell Close-Grip Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"FD5B5AAC-7751-58D7-ACBC-F4258AAC4FAD","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"9A53F81D-BA27-5A94-906C-3554A7840D03","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"C6BBE8AB-A5B4-5B68-8B0F-6632D3067B13","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"B10CEB4A-302F-5E50-92BD-F01D404CD5BD","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DF58FD40-8532-58CA-BF8C-0FD5EEE10248'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"DF58FD40-8532-58CA-BF8C-0FD5EEE10248","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing forward.","Keep your elbows close to your torso and exhale as you curl the weights while contracting your biceps.","Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly begin to lower the bar back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"0D9E56A6-F101-5540-AC1C-B76CBAF844F2","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"00EFFDA2-6ABB-5384-9410-F99BA8AB4022","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B952A7C2-6A88-5915-9DCF-9FE7D5AB99EB","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"4FB7E7F3-5CB2-5F96-BCA7-E4B3B1679185","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('77700D9B-3322-57BE-B188-EE01000F4734'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"77700D9B-3322-57BE-B188-EE01000F4734","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Barbell Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and the barbell on the ground in front of you.","Bend your knees and hinge at the hips to lower your torso and grip the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Keep your back straight and chest lifted as you drive through your heels to lift the barbell off the ground, extending your hips and knees.","As you stand up straight, squeeze your glutes and keep your core engaged.","Lower the barbell back down to the ground by bending at the hips and knees, keeping your back straight.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"3A2AD472-AC55-50CA-AFFF-75A8B37100F1","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"7A2666E1-7EDF-5364-AA5F-7627DA76EEEC","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"1EB86198-DA49-55D6-9A30-2BEB399A6EFB","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"9E820C20-FDF1-540C-8076-D72D19A09634","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B11B46B9-B306-5B01-9D03-A16E36F44573'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"B11B46B9-B306-5B01-9D03-A16E36F44573","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Barbell Decline Bench Press","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with your feet secured and your head lower than your hips.","Grasp the barbell with an overhand grip slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"4A858DDD-66C2-5719-A656-978861E32CBD","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"9DFBB4C6-B893-530D-B240-04251D3EA22B","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"F9166A34-4D66-5459-B671-DAB411E13A49","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E65C6C5E-619B-52EE-9407-979AD6CF13D8","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('607B493C-A887-5258-BD99-22831D1E4B8F'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"607B493C-A887-5258-BD99-22831D1E4B8F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Triceps","Chest"],"name":"Barbell Decline Bent Arm Pullover","notes":"","plannedSets":3,"proTips":["Lie down on a decline bench with your head lower than your hips and your feet secured.","Hold a barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest.","Lower the barbell behind your head in a controlled manner, keeping your arms slightly bent.","Pause for a moment, then raise the barbell back to the starting position by contracting your lats.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"356AA58D-A434-5320-9418-26A53181092B","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"C6EE7A19-1DFD-5226-BCC3-EE85EF043042","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"AB820B70-280A-563E-BB4B-A433258D24E2","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"300344F3-9B4F-5433-BA9B-009D400CA4B5","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('51D84D32-881A-5BAB-BB45-703C391FE527'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"51D84D32-881A-5BAB-BB45-703C391FE527","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Barbell Decline Close Grip To Skull Press","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with your head lower than your feet and hold a barbell with a close grip.","Lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary.","Pause for a moment, then extend your arms to press the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"BF074199-C11B-5317-9041-A4DB7EDBA00D","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"F06D1AEA-B09D-5112-BF09-655A91A22E57","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"639490BA-AE20-5931-8730-00DB2BC823B9","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"73FF13F1-F1B2-5F35-99D7-C55C964412E3","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A1683FCE-BAC4-5115-B4D5-725E21DDAFC4'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"A1683FCE-BAC4-5115-B4D5-725E21DDAFC4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Barbell Decline Pullover","notes":"","plannedSets":3,"proTips":["Lie down on a decline bench with your head lower than your hips and your feet secured.","Hold the barbell with a pronated grip (palms facing away from you) and your hands slightly wider than shoulder-width apart.","Extend your arms above your chest, keeping a slight bend in your elbows.","Lower the barbell in an arc motion behind your head, feeling a stretch in your chest and shoulders.","Pause for a moment, then return the barbell to the starting position by reversing the motion.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"F48525A5-95E9-5CAE-BFC4-35E6C3A1A4C0","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"1C827EC0-1543-5998-AF7F-D39D767B286F","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"FD417629-33EE-58A1-8EAA-54130EA15261","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"06DB3F7B-B4D1-50F8-B98C-D52CB17B3BE2","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EA04CCB5-4B64-5139-90CC-67FAD8EB11A2'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"EA04CCB5-4B64-5139-90CC-67FAD8EB11A2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Barbell Decline Wide-Grip Press","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with your feet secured and your head lower than your hips.","Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.","Lower the barbell to your chest, keeping your elbows out to the sides.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"0D223C46-C7D7-580B-ACCA-37DC86CB92FD","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"259CD9A6-7215-5DF6-8FE0-683B8F77AA3D","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"15B4EF76-545B-5A57-8442-210D3F350CDA","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"4D44753F-5D06-5DAC-90DC-7B338466BA15","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E2531BCB-B67B-51FB-8F6D-DBD20F98118B'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"E2531BCB-B67B-51FB-8F6D-DBD20F98118B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Triceps","Chest"],"name":"Barbell Decline Wide-Grip Pullover","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with your head lower than your hips and your feet secured.","Hold a barbell with a wide grip and extend your arms straight above your chest.","Lower the barbell behind your head in a controlled manner, keeping your arms straight.","Pause for a moment, then raise the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"2E3C2716-1294-504A-B415-B360D317D88D","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"EC45B9F1-64A7-5C3B-9396-18C46956822B","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"7050D1A9-1060-5C54-B92C-278FC8BD294C","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"3B04CFCA-7B94-578B-8FEF-7828F90C9D03","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('995580F3-3D3D-5A60-AEAD-84106CCE8F1A'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"995580F3-3D3D-5A60-AEAD-84106CCE8F1A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Drag Curl","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.","Let the barbell hang at arm''s length in front of your thighs.","Keeping your upper arms stationary, curl the barbell up towards your chest by contracting your biceps.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"F423340A-87AB-554F-A063-A73BACD0E461","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"8136E89F-D4A2-5D74-BCF0-78528C0287A6","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"CE6B2063-36A7-5488-8408-556ED54CF020","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"152E1AFF-B6BB-5EFC-850E-EEC5BBEB0526","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9482390D-F49C-5874-8A95-AED3F4E04838'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"9482390D-F49C-5874-8A95-AED3F4E04838","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings"],"name":"Barbell Floor Calf Raise","notes":"","plannedSets":3,"proTips":["Place a barbell on the floor in front of you.","Stand with the balls of your feet on the edge of the barbell, with your heels hanging off.","Hold onto a stable object for balance if needed.","Raise your heels as high as possible, using your calves to lift your body.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E24A69DB-E08D-5C12-8193-E3D44CA02603","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"21B0FF3D-EF41-55C0-A453-05FF4CB0D376","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"84A0D3D8-C046-52BD-94F0-35DE249613B9","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D3ACE3A0-E4B4-5403-8944-B0C1A341197B","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5D7DB813-DE3B-562F-AA6C-A46B270D5F7F'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"5D7DB813-DE3B-562F-AA6C-A46B270D5F7F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves","Core"],"name":"Barbell Front Chest Squat","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell in front of your chest with your hands shoulder-width apart, elbows pointing forward.","Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"935C55ED-2790-551B-9E00-912C39752B27","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"787A754B-AB84-507F-AAC8-994546CA9E22","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"67AC4CB3-8F97-5CF3-9FB6-F8C486C103F2","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"34B66B24-4140-5E5D-8542-B094A36FC1B1","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('50197A80-E5FA-5EA8-A49A-7EBDF9F16E91'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"50197A80-E5FA-5EA8-A49A-7EBDF9F16E91","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Biceps","Triceps"],"name":"Barbell Front Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip.","Keep your arms straight and lift the barbell forward and upward until it reaches shoulder level.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"2678913B-75B6-5EC4-B960-A58A7594D1DA","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"1D5F12D3-BA28-57E0-87D4-10B8E5773138","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"4B7F8660-7E9D-537C-8B2D-0FA0290331E7","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"C39F00D6-C499-56A3-A8EA-EEE5AE37D260","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E8C999A0-6DAD-5B31-AB9E-4961D84A7BA7'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"E8C999A0-6DAD-5B31-AB9E-4961D84A7BA7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Deltoids","Triceps"],"name":"Barbell Front Raise And Pullover","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.","Keep your arms straight and raise the barbell in front of you until it reaches shoulder height.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Next, lower the barbell behind your head, keeping your arms straight.","Pause for a moment at the bottom, then raise the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"1EE1A377-9AA7-5ED2-8339-C6193FED6A14","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"834EB514-A2EB-5C29-9F2A-47BE12256C60","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"49C3F786-7E16-5806-B6F9-0387BE57EBB6","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"CF0FD3ED-2FC8-5DB8-83D5-11E176D0AE5C","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('60668FE7-C9BA-509C-9FEF-E0B57263D8FC'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"60668FE7-C9BA-509C-9FEF-E0B57263D8FC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves","Core"],"name":"Barbell Front Squat","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell in front of your shoulders, resting it on your collarbone and shoulders.","Engage your core and keep your chest up as you lower your body down into a squat position, pushing your hips back and bending your knees.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"DC2E23BD-0B96-5905-A994-4A931331A5E9","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"9FAE8EDE-B90E-50D7-9B53-1EF162AF4A9C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"2EB19D48-90E5-523C-9EF3-D881F4FBF876","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E97E13C9-F4A0-5EE7-8874-0D0A28E8F34B","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('795D518E-F37D-5DE9-8C41-857869B01D1A'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"795D518E-F37D-5DE9-8C41-857869B01D1A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves","Core"],"name":"Barbell Full Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you begin to lower your body down.","Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.","Lower yourself until your thighs are parallel to the ground or slightly below.","Keep your knees in line with your toes and your weight in your heels.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"7010A4EA-1FD6-5C35-9621-41DEC2EDC610","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"2A3593EE-04C9-5013-A349-74A35F1A9B27","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"EF487858-3F43-521C-9E24-39C954415D83","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"B084AAEB-BE75-5682-8EB1-319FD75298BC","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CD33A643-203D-5A4F-8CF6-8AA23DC23A26'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"CD33A643-203D-5A4F-8CF6-8AA23DC23A26","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves","Core"],"name":"Barbell Full Squat (Back POV)","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you begin to lower your body down.","Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.","Lower your body until your thighs are parallel to the ground or slightly below.","Keep your knees in line with your toes and your weight in your heels.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E3F8560F-9076-5292-9B0E-544502C3882A","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"8FC3042E-EAB1-5720-9ECC-871E9FDE29BD","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"BE00B97E-12AC-5AFF-9E41-B29691B79E25","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"2ADDA2B8-CCC1-5A87-9516-6AB6DF5A4161","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E6B89485-52FA-5F00-AD51-1127030163FC'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"E6B89485-52FA-5F00-AD51-1127030163FC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves","Core"],"name":"Barbell Full Squat (Side POV)","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you begin to lower your body down.","Bend at the knees and hips, pushing your hips back and down as if sitting into a chair.","Lower your body until your thighs are parallel to the ground or slightly below.","Keep your knees in line with your toes and your weight in your heels.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"721AB968-4BBA-5967-85B0-6AEDBCA82D2D","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"158388FA-AD46-5B86-84A2-A0D13BEE88CE","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"79CAFE20-801E-5CF8-B6E2-3FFC81BC3185","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"BAEE989D-8D91-5969-BBFE-0B6D09BEAFCF","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C50EB498-C658-5A21-A24A-3DFEC1129F81'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"C50EB498-C658-5A21-A24A-3DFEC1129F81","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves","Core"],"name":"Barbell Full Zercher Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell in the crooks of your elbows, with your hands gripping the barbell for stability.","Engage your core and keep your chest lifted as you lower your hips back and down into a squat position.","Keep your knees in line with your toes and your weight in your heels.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, squeezing your glutes at the top of the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"53C6219A-57B6-525C-AF58-DE65C9952DF6","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"5D9310B4-A6D0-5124-BAA8-FCA9D001E54C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"919D6B02-930A-5286-B26E-BA56F4CEF8F2","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"AEA22AA5-B078-5901-ADB6-BDAAE4FE10D8","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A2367C33-1BF2-5639-BBE1-B0A24CF38F43'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"A2367C33-1BF2-5639-BBE1-B0A24CF38F43","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Barbell Glute Bridge","notes":"","plannedSets":3,"proTips":["Start by lying flat on your back on the ground with your knees bent and feet flat on the floor.","Place a barbell across your hips, holding it securely with both hands.","Engage your glutes and core muscles, then lift your hips off the ground until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, squeezing your glutes.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"33C38F6E-B230-5FAB-BE45-5DD9DEAD3272","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"F3A37A18-CEA5-52F2-838F-6AFD98FA4AF2","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"CB4F97A7-91C0-5AB4-B2C7-6D7123505EF8","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D4CCAAD5-C589-5F34-87AB-BD132ADCE8AE","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('131D7B4F-344B-5CAC-8CD8-2DFD90C6E5C0'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"131D7B4F-344B-5CAC-8CD8-2DFD90C6E5C0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Core"],"name":"Barbell Glute Bridge Two Legs On Bench","notes":"","plannedSets":3,"proTips":["Start by sitting on the edge of a bench with your upper back resting against it and your feet flat on the ground, hip-width apart.","Place a barbell across your hips, holding it securely with both hands.","Engage your glutes and core muscles, then press through your heels to lift your hips off the bench, creating a straight line from your knees to your shoulders.","Pause for a moment at the top, squeezing your glutes.","Slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"439DC859-DE13-5DF2-B589-E38E3991E304","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"CA0FCDB1-9234-59D6-980D-B082F8A072AB","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"1394E63A-4E79-5ED4-9FC4-444041FB251A","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D00BD89F-C217-57A7-8FE1-2C866D3CA6FA","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('091897B1-FF8B-5CC9-A31E-8F49442B2E55'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"091897B1-FF8B-5CC9-A31E-8F49442B2E55","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Lower Back"],"name":"Barbell Good Morning","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart and the barbell resting on your upper back.","Keeping your back straight and your core engaged, hinge forward at the hips, pushing your buttocks back as if you were trying to touch the wall behind you with your glutes.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Pause for a moment, then return to the starting position by squeezing your glutes and pushing your hips forward.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"982C8A7D-0AD8-55DE-9A5C-6E3CB1D844E8","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"E9AF925A-EC67-5803-9E0B-60D090F2D98B","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"BE203E56-816A-527C-A803-BCEE73D4AD90","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"1C0D1EE7-57B6-5D29-A3B2-EF613133E6E9","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('369D21E9-6DDB-5194-A48F-7E7449526D8F'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"369D21E9-6DDB-5194-A48F-7E7449526D8F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Barbell Guillotine Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lower the barbell slowly towards your neck, keeping your elbows pointed outwards.","Pause for a moment when the barbell is just above your neck.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"B2F9877B-4F28-5D5D-B8F9-B0406564BF96","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"C54C62CF-25DD-5016-8D6A-CC9E1F27BE57","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"1B7D2E79-DBAF-56D2-B063-509003E5A82B","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E17EFCD9-FF8A-5F83-A480-E9984576555E","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('31CD2CB8-C624-55B6-BDFE-AFE0C6B0A48A'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"31CD2CB8-C624-55B6-BDFE-AFE0C6B0A48A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Barbell Hack Squat","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart and your toes slightly turned out.","Hold the barbell behind your legs, resting it on your upper thighs.","Lower your body by bending at the knees and hips, keeping your back straight and your chest up.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"2D21B53A-FD09-5B42-A3C1-5B2ECD7438E0","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"74BA3809-9CFF-53DD-B441-15D7FB8B2B7C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"06FF4582-64AA-5EB6-B9C7-84325300D204","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"874C0937-065A-5A3A-9D61-A9CA1F190DF0","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('010904BA-6AB9-598F-B581-1040461DB5D3'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"010904BA-6AB9-598F-B581-1040461DB5D3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves","Core"],"name":"Barbell High Bar Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes slightly turned out.","Place the barbell on your upper back, resting it on your traps.","Engage your core and keep your chest up as you begin to squat down, pushing your hips back and bending your knees.","Lower yourself until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, extending your hips and knees.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"983A8428-8652-5160-8417-B4973A763CB8","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"2BE93FA2-5372-5094-A235-A8BC93021C13","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"3BA401A7-2BFF-5C42-9DD3-B82429317064","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"3DDC1DC4-148B-5DE7-ABE6-C875EFB6345A","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2C91071C-E861-5C4A-8B0F-FE5379BE747D'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"2C91071C-E861-5C4A-8B0F-FE5379BE747D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Barbell Incline Bench Press","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows at a 45-degree angle.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"7859AACC-CAA1-5BDA-9DAC-AE35712C630A","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"67CA0AB5-C862-56BF-96AE-AB5CF140D0E6","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"D3053B0D-C60A-5A79-9D58-DA3471C53E78","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"390ED78A-282F-522D-BC23-77446D6A35ED","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AC244B68-4FDF-5644-93E4-C2271A115D4A'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"AC244B68-4FDF-5644-93E4-C2271A115D4A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Barbell Incline Close Grip Bench Press","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with a close grip, slightly narrower than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"1FB5C5CF-40FC-55E7-AE86-1AA47822FA85","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"8BF90961-EB44-5FCF-B368-148B773D4C71","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"86B9220F-998C-5854-9FC2-485B199DC8BF","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"EF916D57-E6C6-58AA-90C4-5E4DCBB49949","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('87C3308C-8699-5A4C-88F2-E7BC6A2DDABC'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"87C3308C-8699-5A4C-88F2-E7BC6A2DDABC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Barbell Incline Reverse-Grip Press","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Lie back on the bench and grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.","Unrack the barbell and lower it towards your upper chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"62AE098B-A7AE-55FD-AC60-667DDA6BEF92","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"96DCB935-0120-5BD2-BE57-FCC66D5E1815","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"05F272E9-5BE1-555D-BD0D-6D84033E282A","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E5BF61B0-3139-5D48-8DBC-186CFB62ED7A","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('36B06C6B-80D9-528B-8236-334C92E0E820'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"36B06C6B-80D9-528B-8236-334C92E0E820","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Barbell Incline Row","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Lie face down on the bench with your chest against the pad and your feet flat on the ground.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Keep your back straight and your core engaged.","Pull the barbell towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E4D0E535-1596-5D0D-B166-D38D70440105","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"FCDDEDF4-3DEC-547D-AFE6-319C667C30FB","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"EB67250F-A1DE-5268-B6FA-E55906190535","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"B7DA92B3-A3DB-552B-8ED9-B8060DB4B1DA","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4A627890-78E9-5C7E-BAC4-837E896EA3CE'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"4A627890-78E9-5C7E-BAC4-837E896EA3CE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Serratus Anterior","Deltoids","Trapezius"],"name":"Barbell Incline Shoulder Raise","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Sit on the bench with your back against the pad and feet flat on the ground.","Hold a barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell up to shoulder height, keeping your elbows slightly bent.","Slowly raise the barbell overhead, extending your arms fully.","Pause for a moment at the top, then slowly lower the barbell back to shoulder height.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"26CD719D-6746-5A7E-9156-128D4A70283D","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"908F23A7-53CC-5C00-A51D-AA0D81BCE688","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"DFC236E6-5CF8-5A23-8D88-DE797A22FC6F","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"3B124EA4-7C56-598D-B5CC-EED8CA189ADF","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D34C3627-770C-5F44-8094-E570CC1BA7E3'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"D34C3627-770C-5F44-8094-E570CC1BA7E3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Barbell Jefferson Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell with an overhand grip, resting it on the front of your body, just below your waist.","Step your left foot forward and your right foot back, keeping your feet shoulder-width apart.","Bend your knees and lower your body down into a squat position, keeping your back straight and chest up.","Push through your heels to stand back up to the starting position.","Repeat the movement, alternating your forward and back foot with each repetition."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"A752D66E-DC76-5254-96AF-D3CFA6222095","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"383257B9-0368-5539-9B44-CCC62C6E2ED5","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"5E8089F3-1DFA-561F-9A99-560F0EB0077A","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"760D665E-AC8C-5A1C-9AFD-76ECA3CA63CD","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B873D7C8-2A48-5090-A599-C67C5A878FC8'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"B873D7C8-2A48-5090-A599-C67C5A878FC8","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Barbell Jm Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lower the barbell to your chest, keeping your elbows tucked in close to your body.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"D435A9A5-2EA4-5DD0-9A48-593706F1E204","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"A15423A8-047E-5201-A391-494E8B8F6864","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"63CE7E05-9718-5231-8253-5EB87FD66ADB","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"0D8FE8AD-3213-5B11-9C71-1E1B77A999D5","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4F1C267E-921B-5FC7-9E8A-67E90CB1304F'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"4F1C267E-921B-5FC7-9E8A-67E90CB1304F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Barbell Jump Squat","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.","Lower your body into a squat position by bending your knees and pushing your hips back.","Once you reach the bottom of the squat, explode upwards by jumping off the ground.","As you jump, extend your hips, knees, and ankles, pushing through your toes.","Land softly back into the squat position and immediately repeat the movement for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"5BC16D40-83AC-50C0-B17E-89F85E74851E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"AE13AB1A-BC95-5287-B5FA-BD5CB70A1BFE","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"A1D85406-5B41-53E9-8727-9A353DA4D12F","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"0AC6A40E-43FB-59B8-B3B8-F0D62C35C5E1","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E5749EB0-E46F-520C-ADC8-4B0880254E43'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"E5749EB0-E46F-520C-ADC8-4B0880254E43","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Barbell Lateral Lunge","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a barbell across your upper back.","Take a big step to the side with your right foot, keeping your left foot planted.","Bend your right knee and lower your body down into a lunge position, keeping your left leg straight.","Push off with your right foot and return to the starting position.","Repeat on the other side, stepping with your left foot."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"A1D6A2D4-22CE-5754-A73A-E8BE32B4E458","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"D34A2CBF-6115-5ADF-A6E3-C2A5232B0989","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"8DA6E36F-068C-5BDE-8C83-132E3E2AE04C","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E308569E-F4F7-5233-9E62-E217FD68C732","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0D75AE2B-D109-5472-8F6E-F364DD10A83D'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"0D75AE2B-D109-5472-8F6E-F364DD10A83D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Barbell Low Bar Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and the barbell resting on your upper back.","Keeping your chest up and core engaged, slowly lower your body by bending your knees and pushing your hips back.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"AA08022E-5456-5972-9BDD-237768334974","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"06A9CCA7-8821-5158-99AC-D2329EEE1C51","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"F39BDAE4-172A-55E5-AC5E-083CB5859A23","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"157152AD-B408-5EA5-88CA-867FDF610FC8","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E6E92816-413B-5959-9710-6CD40132C6DC'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"E6E92816-413B-5959-9710-6CD40132C6DC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Barbell Lunge","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart and a barbell resting on your upper back.","Take a step forward with your right foot, keeping your torso upright.","Lower your body by bending your right knee until your thigh is parallel to the ground.","Push through your right heel to return to the starting position.","Repeat with your left leg, alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"0A784F8C-6849-5111-B713-9F0E78953581","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"44F4ECBA-B9E6-5D97-9E85-F450B0D25CEB","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"7A1A520F-8B11-5B22-B82D-18147B807E27","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"58B98592-180A-598A-8C1F-2EEBD62C57A6","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('566E471B-7BA1-51F0-BEF5-7DFF75D47EAA'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"566E471B-7BA1-51F0-BEF5-7DFF75D47EAA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Barbell Lying Back Of The Head Tricep Extension","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold a barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"C95B096A-9F33-5CA2-A444-3541EC953A0B","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"048D6B52-FC92-5D29-8DCD-812D9E99D88F","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"5E5D1E11-3EE9-55CC-8DEE-DD3BD7B14DAD","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"74997307-2145-586C-BF8C-FD809830065A","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DD3F6D25-CB52-5B6A-8DF3-6D132B7A744F'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"DD3F6D25-CB52-5B6A-8DF3-6D132B7A744F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Barbell Lying Close-Grip Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a close grip, hands shoulder-width apart, palms facing towards your feet.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Slowly lower the barbell towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell touches your chest, then push it back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"A2A8D9D6-C62D-59E5-BAEF-589A5B56EB87","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"D1F9E9E5-D7DF-525A-BB67-9A2CBDE2D81C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"CC47831F-6A7A-57E8-8E7B-4B53B7F988C9","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"5AF4B209-B2E7-580D-9E7A-F2274BDAA8E4","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4FF62A44-C424-58C6-9432-6FD66976A96C'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"4FF62A44-C424-58C6-9432-6FD66976A96C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Barbell Lying Close-Grip Triceps Extension","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Grasp the barbell with a close grip, hands shoulder-width apart, palms facing up.","Extend your arms fully, lifting the barbell above your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment at the bottom, then extend your arms back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"DCB25F06-868C-5EB1-8838-80BEB252475E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"EAE202F7-D718-5FC5-8E4C-0ED8880B9FC9","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"D66303BB-CDE8-57A7-A68D-C24F66EB15CD","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"DE7F0A00-B2A7-594A-9B39-4C2156DA456D","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('04072A7E-EACD-5C51-9D80-BA6AC9ACA17C'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"04072A7E-EACD-5C51-9D80-BA6AC9ACA17C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Barbell Lying Extension","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"8F0D240B-B91E-56BB-AF96-FADCDA7202EB","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"F0B2B650-2541-5105-B3B1-E3AEFE9FC0AB","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"35CFA782-5E78-558D-A937-E60D5F72FAB5","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"1AB370E6-8488-5B05-8833-663FF152E101","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FC1D2553-5D57-58A3-A352-9800F3DE1DEC'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"FC1D2553-5D57-58A3-A352-9800F3DE1DEC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps"],"name":"Barbell Lying Lifting (On Hip)","notes":"","plannedSets":3,"proTips":["Lie flat on your back on a bench with your feet flat on the ground and your knees bent.","Hold the barbell with an overhand grip and position it on your hips.","Engaging your glutes, lift your hips off the bench until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"00D108AD-FE27-59BB-B6EC-40BA26B1CCF8","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"23DBDFA0-9C53-5B7E-98D8-DF0B0091DBEC","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"0D45529E-13F3-5A8B-AA5B-9F78F5A67A3A","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"B8F3C9CD-6256-55B9-B938-024A83A7A881","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F3E4627E-4BF9-5791-983D-468038D819A6'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"F3E4627E-4BF9-5791-983D-468038D819A6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Lying Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher bench with your chest against the pad and your arms extended over the edge, holding a barbell with an underhand grip.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"92B5020A-09B8-5CBD-A9C8-3065A030290F","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"1F3B4D66-5078-5B9B-B4F9-A8BD4F597DE9","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"6F369594-093A-5A4E-B961-CCB2C3F988AF","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"B4C29043-9DC2-5261-8B30-DFB8DE1C64B0","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BD438293-392F-50D7-B512-AB3C6F807857'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"BD438293-392F-50D7-B512-AB3C6F807857","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Barbell Lying Triceps Extension","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment at the bottom, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"F05AE650-ECC9-535A-ABB0-170823264155","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"2E7C3790-92BD-5BE8-9E28-D4C27A98DEF6","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"650D5CE0-E61B-5661-AF21-8025C553CCC1","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"8DF53FD5-9A8F-5BF5-897C-FBC13EFC405C","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E2477CB4-F832-5F7F-886D-5E675A7D7F67'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"E2477CB4-F832-5F7F-886D-5E675A7D7F67","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Barbell Lying Triceps Extension Skull Crusher","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with an overhand grip, hands shoulder-width apart, and extend your arms straight up over your chest.","Keeping your upper arms stationary, slowly lower the barbell towards your forehead by bending your elbows.","Pause for a moment when the barbell is just above your forehead, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"16F2B9AE-C1B4-5759-A48F-D2477E6DDE96","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"3480DA87-F5B9-539D-8092-7F4DC536B134","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"F0A8A440-BA24-52FA-984A-F1D8B438205F","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"3E60ED75-2393-59B4-BF64-2C41F61DE201","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AF02E7D0-EBFF-53B0-B153-EBDD733DDC6E'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"AF02E7D0-EBFF-53B0-B153-EBDD733DDC6E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Barbell Narrow Stance Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and toes pointing slightly outward.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you slowly lower your body by bending your knees and pushing your hips back.","Continue lowering until your thighs are parallel to the ground or slightly below.","Pause for a moment, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"082C8068-EB4B-55AC-A974-9A67B1E9A521","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"0677C435-0753-5C3A-B417-75D34A86E0FF","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"894C45AA-242A-52BA-A9A3-DD1465E8BF9A","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"564054B5-79B1-568A-B06D-6E19C92DDEBC","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('28C8F0AF-113C-524D-A1E9-EB9460BCB539'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"28C8F0AF-113C-524D-A1E9-EB9460BCB539","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Barbell One Arm Bent Over Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, knees slightly bent, and hold a barbell with one hand using an overhand grip.","Bend forward at the hips, keeping your back straight and your head in a neutral position.","Pull the barbell up towards your chest, keeping your elbow close to your body and squeezing your shoulder blades together.","Lower the barbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions, then switch to the other arm."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"8545C362-7D1D-539B-8511-AA06FDC1AA55","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"ECA042D7-A68C-5DA6-9E56-5214CFFCFC76","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"515BA55A-3394-55C9-B4AF-C96A3398F1FC","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"AFEDE2CC-F1DF-511B-9F58-3E66387B7156","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A9EC87A8-6980-5C2B-BA0C-51330BAF169F'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"A9EC87A8-6980-5C2B-BA0C-51330BAF169F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Barbell One Arm Floor Press","notes":"","plannedSets":3,"proTips":["Lie flat on your back on the floor with your knees bent and feet flat on the ground.","Hold the barbell with one hand, palm facing up, and extend your arm straight up over your chest.","Slowly lower the barbell towards your chest, keeping your elbow close to your body.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"2019F7C9-8144-529D-A16C-DD2C370B1587","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"8BB2D7E0-A1DD-56BE-A2AB-E7FD45BC1CDF","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"01DF1C85-0112-59BA-855C-EF0773C44B7D","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"A3782150-459B-5F16-9B4A-CB5BA1397899","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A95D3237-4CE6-5A50-AED1-A463719D7C59'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"A95D3237-4CE6-5A50-AED1-A463719D7C59","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Lower Back"],"name":"Barbell One Arm Side Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a barbell in one hand with an overhand grip.","Keep your back straight and your core engaged.","Bend at the hips and lower the barbell towards the outside of your leg, keeping your arm straight and your chest up.","Lower the barbell as far as you can while maintaining good form.","Pause for a moment, then slowly return to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"1E6AE634-4E3F-52EF-8CF3-47E6168274CF","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"2031650A-751C-5874-895F-A4338511AE2B","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"CBA70177-433A-5821-9CC4-1DA2FCE78E9C","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"3FD36CD6-1D3A-5EBA-972D-9DCF056191F8","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4145B395-C248-5C06-88B4-F93D52EE3C67'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"4145B395-C248-5C06-88B4-F93D52EE3C67","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Forearms","Core"],"name":"Barbell One Arm Snatch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes pointing slightly outwards.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend your knees and lower your hips into a squat position, keeping your back straight and chest up.","Explosively extend your hips, knees, and ankles, driving the barbell upwards.","As the barbell reaches chest level, pull it upwards with your arm, keeping it close to your body.","Rotate your elbow under the barbell and extend your arm fully overhead, locking out your elbow.","Lower the barbell back down to the starting position in a controlled manner.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"15809902-6BA3-5709-A020-9E4C4F4E1E03","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"6DC813BF-0904-5955-8490-DFE796F930A2","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"4459F0EF-3889-57FD-8BA3-5B943888BAB6","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"63F5AA84-DBF3-503C-809E-8B912158B765","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('ED13E5E5-1A41-5F76-853F-F2072A712144'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"ED13E5E5-1A41-5F76-853F-F2072A712144","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Barbell One Leg Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell across your upper back.","Lift one foot off the ground and extend it forward, keeping it parallel to the ground.","Bend your standing leg and lower your body down as if sitting back into a chair, keeping your chest up and your back straight.","Lower yourself until your thigh is parallel to the ground, then push through your heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs and repeat."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"E6C22C30-BFB1-5A1E-8A39-5059670F94AA","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"0BBF257A-6E89-5AD4-B8CA-F26648F18A61","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"C600B064-1AE9-5B96-90EB-FB39DFB80BEA","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"685DFE2F-797B-5CB5-8809-7D3C7B403AD4","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('70DB312B-C7FD-55AB-AD77-988624D622F2'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"70DB312B-C7FD-55AB-AD77-988624D622F2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves","Core"],"name":"Barbell Overhead Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell with a wide grip, positioning it overhead with your arms fully extended.","Engage your core and lower your body down into a squat position, keeping your chest up and knees tracking over your toes.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"1AF67608-18DB-58F0-A9E1-02E36256E349","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"5CBE21A5-30DC-54E2-9BB9-00830658564D","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"F0CFBA15-8277-59E8-94F0-9FF80C902622","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"DEABDC32-CB03-5F25-8217-E4C764A70C2B","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('41CC7D77-26D2-5F42-9172-424A5A42034C'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"41CC7D77-26D2-5F42-9172-424A5A42034C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Barbell Palms Down Wrist Curl Over A Bench","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, palms facing down.","Hold a barbell with an overhand grip, hands shoulder-width apart.","Lower the barbell towards the ground by flexing your wrists, keeping your forearms stationary.","Pause for a moment at the bottom, then slowly raise the barbell back up by extending your wrists.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"EABDE00B-A7F3-51A2-976E-8F233EA31D47","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"C4B39F78-99A7-58F6-8A24-098A52E5121C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"901C110F-47B5-5E06-AE8B-133BEE72D338","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"54019576-A30B-5BEC-B118-442D5C2D121A","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('91827BDB-46BB-53CD-ABDB-5D045AE11465'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"91827BDB-46BB-53CD-ABDB-5D045AE11465","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Shoulders"],"name":"Barbell Palms Up Wrist Curl Over A Bench","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a barbell with an underhand grip, palms facing up.","Rest your forearms on the bench, allowing your wrists to hang off the edge.","Keeping your forearms stationary, exhale and curl your wrists upwards as far as possible.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"01C5447D-219C-5DF8-BF7B-E8ED10B6034F","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"3F728CE5-156F-5D82-9BF1-7001913DD39C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"C1DF596F-7668-53AF-9238-8065660F190B","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"9BABEB60-F956-5B08-9C97-97710318376F","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('754FBAE9-4730-50B5-9E0D-F37CBD1A2C1B'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"754FBAE9-4730-50B5-9E0D-F37CBD1A2C1B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Barbell Pendlay Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Bend forward at the hips, keeping your back straight and your chest up.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Pull the barbell towards your upper abdomen, squeezing your shoulder blades together.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"4AB8ABE3-E0C7-5199-8C5F-BE658B999323","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"BE7CDE65-1296-5E78-BE06-2E3365C54401","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"3CBB9EE1-410F-5465-ADD9-51DD3A1C16B1","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"EFE2859F-BC5C-5595-BF61-D07503D65632","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('46610FAA-8CBA-595C-BF1F-586BAC1293A5'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"46610FAA-8CBA-595C-BF1F-586BAC1293A5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Barbell Pin Presses","notes":"","plannedSets":3,"proTips":["Set up a barbell on a power rack at chest height.","Stand facing the barbell and position yourself underneath it, with your feet shoulder-width apart.","Grip the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest, with your arms fully extended.","Lower the barbell down towards your chest, keeping your elbows tucked in close to your body.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"0233493E-B146-5857-B292-EF4C5AC4AAF1","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"69276551-9BF8-55BC-A1C8-28D70B04256A","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"09E6C9E0-F23D-5315-8C69-0EF7D23827B4","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"CB8E3F65-0F73-5751-BC2C-256413C48847","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('4C305BDD-4B44-561E-877E-5576277DD3A3'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"4C305BDD-4B44-561E-877E-5576277DD3A3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher bench with your upper arms resting on the pad and your chest against the support.","Grasp the barbell with an underhand grip, slightly wider than shoulder-width apart.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"D044A09E-5373-5B24-B076-A3948D6ED94D","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"1DDDF22F-C547-5D56-962A-20B1E92E5C84","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"A390ACB5-324D-5C34-9C4A-98E222DBDAA2","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"C160AA76-3A5C-5C8A-953A-69009047D9F3","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('48C0951B-24BB-59C9-ABBB-310DAB93A6F3'::uuid, '{"category":"Core","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"48C0951B-24BB-59C9-ABBB-310DAB93A6F3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Chest"],"name":"Barbell Press Sit-Up","notes":"","plannedSets":3,"proTips":["Lie flat on your back on a mat with your knees bent and feet flat on the ground.","Hold the barbell with an overhand grip, resting it on your chest.","Engaging your abs, slowly lift your upper body off the ground, curling forward until your torso is at a 45-degree angle.","Pause for a moment at the top, then slowly lower your upper body back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"ED714E97-A3C9-5F1F-A783-B02915CD8EA3","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"5FBA5ABA-2131-55CF-8B27-CDC9F2A7023C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"25A2CFD1-F276-501C-8648-343B1922E949","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"EC317899-AE74-5D56-BC67-86E4EEDDB706","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9A608BCC-B390-54E4-90E2-DEA6F75AC7C7'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"9A608BCC-B390-54E4-90E2-DEA6F75AC7C7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Prone Incline Curl","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Lie face down on the bench with your chest and stomach resting against it.","Hold a barbell with an underhand grip, shoulder-width apart.","Extend your arms fully, allowing the barbell to hang down towards the floor.","Keeping your upper arms stationary, exhale and curl the weights while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"4932B680-2A68-5161-8BB9-04B473071CA7","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"F76F72E6-C9D4-5EC0-8196-10C577202985","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"9D93E9DE-FAAE-5E6D-9ED7-376FC69E9D57","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"722EE281-4B0E-57B2-987B-BA7A5AE61424","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('48D0EAB3-4F12-549A-B5C8-30D8B8A98ED6'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"48D0EAB3-4F12-549A-B5C8-30D8B8A98ED6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Chest","Triceps"],"name":"Barbell Pullover","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your head at one end and your feet on the floor.","Hold a barbell with a shoulder-width grip and extend your arms straight above your chest.","Keeping your arms straight, lower the barbell behind your head in a controlled manner until you feel a stretch in your lats.","Pause for a moment, then raise the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"93ACC4D2-1362-5454-A391-183801E036B8","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"E6ACBF2E-89C2-56BC-8A92-C053894221ED","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"589459C3-623A-5915-937A-63A3EC8F67FF","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"25B74D06-2ABB-5EAF-9944-BD35025607D8","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2941B869-7021-5013-B2B7-1CFFE783C7A0'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"2941B869-7021-5013-B2B7-1CFFE783C7A0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Triceps","Chest","Shoulders"],"name":"Barbell Pullover To Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your head at one end and your feet on the ground.","Hold the barbell with a pronated grip (palms facing away from you) and extend your arms straight above your chest.","Keeping your arms straight, lower the barbell behind your head in an arc-like motion until you feel a stretch in your lats.","Pause for a moment, then reverse the motion and press the barbell back to the starting position above your chest.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"93B8D39C-2241-50EC-88AA-0F350503F272","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"E0B5E104-3E28-5284-8CB5-D991069815C9","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"3024A675-574E-5265-9D87-739525F9A4DC","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"19938769-8322-5E81-A6AE-98A362BF9B56","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1633FD77-7DAE-51E0-A4DF-E22A0A524215'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"1633FD77-7DAE-51E0-A4DF-E22A0A524215","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Barbell Rack Pull","notes":"","plannedSets":3,"proTips":["Set up a barbell on a rack at knee height.","Stand with your feet shoulder-width apart, toes pointing slightly outwards.","Bend at the hips and knees to lower yourself down and grip the barbell with an overhand grip, hands shoulder-width apart.","Engage your core and lift the barbell by extending your hips and knees, pulling your shoulders back and squeezing your glutes at the top.","Lower the barbell back down to the starting position by bending at the hips and knees.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"DD226113-BDD9-5789-B898-45CECD26C47B","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"AA815870-CB29-5664-82BC-1B50B07D042B","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"1331641F-D525-517E-8F78-A2EED90EC56C","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"5386B9EE-3AFA-5331-A0EF-48F1BD34CD84","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3FF57902-6621-5854-8D0B-DB8262F5CD00'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"3FF57902-6621-5854-8D0B-DB8262F5CD00","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Rhomboids"],"name":"Barbell Rear Delt Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.","Bend your knees slightly and hinge forward at the hips, keeping your back straight.","Raise the barbell out to the sides, keeping your arms straight, until they are parallel to the ground.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"C4F9039B-4A31-566C-88FD-E7B25B4E598D","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"AA9CDC3D-AE67-5952-A120-5B6C643261FA","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"53060336-436B-5F7F-A3E3-5124E725D812","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"EA072C0D-AB4D-57CA-8A81-4E9DEE921DB2","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('21308112-F705-5719-80A9-EA21638B8683'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"21308112-F705-5719-80A9-EA21638B8683","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Trapezius","Rhomboids","Biceps"],"name":"Barbell Rear Delt Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up.","Pull the barbell towards your chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"953FBDCA-8EF5-54FE-8073-F3F96F27FF1E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"88F408F3-DEB3-5782-ABEC-3D184FB0858B","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B931E94A-A572-5B82-8AE8-CF6A5365050A","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D52D7911-924B-507C-B267-5E05695170D2","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B151A18F-AB49-59E3-8608-7D04D0C18B3A'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"B151A18F-AB49-59E3-8608-7D04D0C18B3A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Barbell Rear Lunge","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart and a barbell resting on your upper back.","Take a step backward with your right foot, landing on the ball of your foot.","Bend both knees to lower your body until your left thigh is parallel to the ground.","Push through your left heel to return to the starting position.","Repeat with the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"DA0575F0-43D8-532C-B44F-F2FB5D630211","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"79D10BF7-8ECD-56EF-9BC9-044FC0690E0E","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"2BAA21B3-7202-54F4-8AC7-27771EDB7DFA","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"F8A49FE9-A9E6-5A0A-97CB-1E723087BF93","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('009A91D2-4B03-597F-933A-00D79DCD696E'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"009A91D2-4B03-597F-933A-00D79DCD696E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Barbell Rear Lunge V. 2","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell across your upper back.","Take a step backward with your right foot, landing on the ball of your foot.","Bend both knees to lower your body until your left thigh is parallel to the ground.","Push through your left heel to return to the starting position.","Repeat with the other leg."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"DE32D579-0869-51C0-83FB-602486CE87BE","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"078A00F9-051C-5FEB-B041-989E0FB9881D","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"EE70577A-DBCA-546E-9108-101CACEB3211","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"7AD6F4F8-E24B-5BA8-BD73-B3F5C8226A40","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('15C7D765-7E70-508E-902F-BFB877661C77'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"15C7D765-7E70-508E-902F-BFB877661C77","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Barbell Revers Wrist Curl V. 2","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and your knees bent.","Hold a barbell with an overhand grip, palms facing down, and your hands shoulder-width apart.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Keeping your forearms stationary, exhale and curl your wrists upward as far as possible.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"60F94420-6F05-511E-97BF-826E91C6B3A2","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"98C2986D-046C-50DD-979B-31B7956ACC3C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"3700CAA3-4A2B-5D96-A4CB-AA00597FCDAF","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"28E06511-9B7E-5617-B9AE-2512E5CF22A4","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6E3904A6-082C-5110-AE29-34C8BFDD5FD9'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"6E3904A6-082C-5110-AE29-34C8BFDD5FD9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Barbell Reverse Close-Grip Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a reverse grip, hands shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Slowly lower the barbell down towards your chest, keeping your elbows close to your body.","Pause for a moment when the barbell is just above your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"44643AF8-85D0-5F7E-94F8-DB94E206208E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"795CAB72-2771-5875-B9AB-5F58920CCD37","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"9BC377E3-8C29-5800-8335-A203B382F2F4","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"F1C229B2-47A5-53B0-A7DA-2B93820D96C9","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('20C3FCD5-5BB7-5A45-BEA4-6D48320A7A08'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"20C3FCD5-5BB7-5A45-BEA4-6D48320A7A08","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Reverse Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, palms facing down.","Keep your upper arms stationary and exhale as you curl the barbell upward, contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly lower the barbell back to the starting position, keeping your upper arms stationary.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"8D81727B-3869-5AB8-BC19-C8206C84B1D4","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"BC06C226-A07D-5449-A00A-E46103FDF8ED","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"7D91D769-AC55-59D6-B206-2EDEF43AB047","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"5B801B06-BF60-57F5-A72E-7FA13534CA4D","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F07E7E6E-FEF5-5DA2-B6EF-2EB18AA4D22B'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"F07E7E6E-FEF5-5DA2-B6EF-2EB18AA4D22B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Barbell Reverse Grip Bent Over Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold a barbell with an overhand grip, palms facing down, and hands slightly wider than shoulder-width apart.","Bend forward at the hips, keeping your back straight and chest up, until your torso is almost parallel to the floor.","Pull the barbell towards your lower chest, squeezing your shoulder blades together.","Pause for a moment at the top, then slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"0BDDEDB5-4BB9-57F8-9766-CDC9AC6D9CD6","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"2F41C556-FC5E-5896-91E5-53104EFAC014","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"0E958019-DF73-5169-A51E-35AB96589D43","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"7705B2BB-0DEF-5E4F-BDC7-DE29BBB36B79","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C07DEBC1-4BC8-50BD-926D-55A8A0CFAE80'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"C07DEBC1-4BC8-50BD-926D-55A8A0CFAE80","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Barbell Reverse Grip Decline Bench Press","notes":"","plannedSets":3,"proTips":["Lie on a decline bench with your feet secured and your head lower than your hips.","Grasp the barbell with a reverse grip, slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment at the bottom, then push the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"30D2CAD3-06B1-5135-8901-E81779666BDB","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"13C82FD7-B34C-592E-9DCA-2315E62F93EB","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"D37CC796-6EF1-57D1-A4C9-692CDB790EC6","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"03006903-7F49-53CC-ADBA-64F1F367B8D4","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CC9BE28B-57EA-52DC-B202-5E7573D02864'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"CC9BE28B-57EA-52DC-B202-5E7573D02864","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Barbell Reverse Grip Incline Bench Press","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Lie down on the bench with your feet flat on the ground.","Grasp the barbell with a reverse grip, hands slightly wider than shoulder-width apart.","Unrack the barbell and lower it slowly towards your chest, keeping your elbows tucked in.","Pause for a moment when the barbell touches your chest.","Push the barbell back up to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"D427DD50-2921-59D5-96E1-9920A1A3616C","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"17EC68D8-810A-5517-BF87-05CB89DFB858","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"5CF8ACFB-0D96-53E1-9F91-DAFA8A4430D7","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"EABB892A-8DFE-595A-8D40-1DA87CDC3877","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('40F130FB-3546-5569-99E2-706721FE0F19'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"40F130FB-3546-5569-99E2-706721FE0F19","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Upper Back","Biceps","Forearms"],"name":"Barbell Reverse Grip Incline Bench Row","notes":"","plannedSets":3,"proTips":["Set up an incline bench at a 45-degree angle.","Sit on the bench facing the backrest with your chest against it.","Grab the barbell with a reverse grip (palms facing down) and hands slightly wider than shoulder-width apart.","Keep your back straight and core engaged.","Pull the barbell towards your upper abdomen, squeezing your shoulder blades together.","Pause for a moment at the top of the movement.","Slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"6B1D9F00-60B1-5C8C-BFC2-8D0B9DD58FC5","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"27069485-B306-5B07-9B4C-52CD3E99BB1C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"0180FBE2-5B8F-568F-BB0F-143C9D12EC61","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"DCD3F6F9-7A3E-5292-A7DD-EB0D2DCB3790","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6BA8A214-D305-5572-ADDD-44D8B89000EE'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"6BA8A214-D305-5572-ADDD-44D8B89000EE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Forearms"],"name":"Barbell Reverse Grip Skullcrusher","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your head at the end of the bench.","Hold the barbell with a reverse grip, palms facing towards your face, and your hands shoulder-width apart.","Extend your arms straight up over your chest, keeping your elbows in and your wrists straight.","Slowly lower the barbell towards your forehead by bending your elbows, keeping your upper arms stationary.","Pause for a moment at the bottom, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"BAEA00CF-AFFA-578D-87B6-589B7ECDCC56","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"EC725E32-A632-5786-8A75-1367AA3FA68D","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"A30C5349-B14F-599F-A2D3-389E2488EAE1","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"41749276-7E48-5734-A98D-E3FCC6D06E51","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('012DE386-0657-57CE-9F9B-0D137F5E6250'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"012DE386-0657-57CE-9F9B-0D137F5E6250","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Reverse Preacher Curl","notes":"","plannedSets":3,"proTips":["Sit on a preacher bench with your chest against the pad and your arms extended straight down, holding a barbell with an overhand grip.","Keeping your upper arms stationary, exhale and curl the barbell upward while contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"BBCC1018-DE50-5F44-B961-1F5EFF18F11E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"64E6837D-0508-51ED-B591-D973211B8B2C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"1E719478-F49B-5F62-AA7F-45B17BE30D18","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"FEDA4935-0F5B-5706-8D7F-625E51E57D2F","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('22436E50-5F3C-51A1-8BF2-07EA10FECDB3'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"22436E50-5F3C-51A1-8BF2-07EA10FECDB3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Barbell Reverse Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and hold a barbell with an overhand grip, palms facing down.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the barbell towards your body.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"4FA85315-0967-537B-AFF5-3E5AF432E3E9","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"D79E9316-9AB8-5770-9547-C878D07C8F48","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"41949C46-A8CD-5A8E-B4E4-E7B6510F5E85","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"8C0375BE-4335-5365-876E-8F3A2BF6C63D","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('56B985DB-9839-51F7-A315-F6F6D16CCE75'::uuid, '{"category":"Core","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"56B985DB-9839-51F7-A315-F6F6D16CCE75","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Lower Back"],"name":"Barbell Rollerout","notes":"","plannedSets":3,"proTips":["Kneel on the floor and hold a barbell with both hands, shoulder-width apart.","Roll the barbell forward, extending your arms and keeping your core engaged.","Continue rolling forward until your body is fully extended and your arms are overhead.","Pause for a moment, then slowly roll the barbell back towards your knees, maintaining control.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"0738C8E0-E03B-5A1A-A357-8739E283E17E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"8C9F04B2-3C73-55E6-A31A-69D3AE460930","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"7E121CA8-7F16-5C42-B971-3ABED60D4F95","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"33AA5175-5754-53C3-87B7-EAC850449532","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BE95C4A4-B344-5457-A219-0D263720B489'::uuid, '{"category":"Core","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"BE95C4A4-B344-5457-A219-0D263720B489","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Triceps"],"name":"Barbell Rollerout From Bench","notes":"","plannedSets":3,"proTips":["Start by kneeling on the floor with a barbell placed on a bench in front of you.","Grasp the barbell with an overhand grip, slightly wider than shoulder-width apart.","Keeping your core engaged and your back straight, slowly roll the barbell forward, extending your arms in front of you.","Continue rolling the barbell forward until your body is fully extended and your arms are overhead.","Pause for a moment at the fully extended position, then slowly roll the barbell back towards your body, returning to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"D5F0FB8E-06E7-5133-9D5F-FEE7F24B2B9C","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"B56575E6-DC87-576C-9775-77AB640283E5","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"75537491-51FF-53A3-8AE9-A092747B2266","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"ED86F833-2483-5302-B62C-02A3A7D6E6BC","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('38CD6250-9AF1-570C-A321-50BE03D0E15A'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"38CD6250-9AF1-570C-A321-50BE03D0E15A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Barbell Romanian Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your toes pointing forward.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend at the hips, keeping your back straight and your knees slightly bent.","Lower the barbell towards the ground, keeping it close to your body.","Feel the stretch in your hamstrings as you lower the barbell.","Once you feel a stretch in your hamstrings, push your hips forward and stand up straight.","Squeeze your glutes at the top of the movement.","Lower the barbell back down to the starting position and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"45E838B3-12CD-5234-8292-157E521E75EA","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"454E67FF-60D7-51E4-B5D5-972CE1F2AB55","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B365B489-3C83-5D2D-9D77-F174730DEDBB","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"288F6287-69C6-5A41-BACA-A937DACF40E2","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('26D84CEF-B236-5835-9DB4-CC0DCBEFF576'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"26D84CEF-B236-5835-9DB4-CC0DCBEFF576","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Barbell Seated Behind Head Military Press","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and bring it down to shoulder level, behind your head.","Press the barbell upward until your arms are fully extended.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"9A95A040-AD55-5335-91F3-2660C6551856","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"789558BE-A1DF-5BCE-9487-0842F8E81E47","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B6C6000F-0596-5B97-BCF3-94348F691B31","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"ECD5A14D-ACA5-5A95-A04B-121CCC01D808","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('707CBEA6-2363-50E0-9F93-184CA5756AAF'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"707CBEA6-2363-50E0-9F93-184CA5756AAF","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Barbell Seated Bradford Rocky Press","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell to shoulder height, keeping your elbows slightly bent and pointing forward.","Press the barbell overhead, fully extending your arms.","Lower the barbell back to shoulder height and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"CF08BF36-BDBC-5830-BBAA-222A19B109B3","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"228A1C02-035E-58A3-8B4F-55A62AFE2C79","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"D864ED8B-5CF1-5675-8623-B47A86694B2C","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"C047AD6A-1E58-57E2-976B-B31BE6319716","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('513CBE31-919D-5DF9-830D-22A30A4FA727'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"513CBE31-919D-5DF9-830D-22A30A4FA727","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Quadriceps"],"name":"Barbell Seated Calf Raise","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the floor and a barbell resting on your thighs.","Place the balls of your feet on a raised platform, such as a block or step.","Position the barbell across your thighs and hold it securely with your hands.","Keeping your back straight and your core engaged, lift your heels off the ground by extending your ankles.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"34504716-C906-5BBA-8544-4BFE2A682137","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"C02EA95D-1E7D-5A37-BAE7-B2F594FB0B57","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"A5B47545-19E1-5314-9D8A-E7D000DE3B59","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"81BDBF50-BBBE-51D2-8969-D58F9E6BD3D4","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('58363A25-C652-5745-AC6F-9A9180899E9A'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"58363A25-C652-5745-AC6F-9A9180899E9A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Barbell Seated Close Grip Behind Neck Triceps Extension","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with a close grip behind your neck, palms facing forward.","Keep your elbows close to your head and slowly lower the barbell towards the back of your head.","Pause for a moment, then extend your arms back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"08357DC6-3584-5B8D-B76E-48F5F9BF29F1","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"E68FD488-0DD1-5F18-8170-6E7FAA00A5D6","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"5CC25942-C1C9-58B6-8891-F190D2015D81","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"8A79D69E-A919-5AEB-9140-E4657B841E0A","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('63A79F38-D1D2-5EE8-BDE8-3BFC4DF96F3C'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"63A79F38-D1D2-5EE8-BDE8-3BFC4DF96F3C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Seated Close-Grip Concentration Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the floor and hold a barbell with an underhand grip, hands shoulder-width apart.","Rest your upper arms against your inner thighs, just above your knees, and let the barbell hang down in front of you.","Keeping your upper arms stationary, exhale and curl the barbell up towards your shoulders, contracting your biceps.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"516A4849-0963-5988-A44E-561F9F82AF93","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"A347BF19-EE16-593E-A205-231348E2634C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"18CDA416-71A7-5C61-AC16-3D37C58AB01D","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"556143BE-F8A5-538A-A655-97B81A6EF3B7","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DC5F935A-E105-5480-9E1F-B9D475210D86'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"DC5F935A-E105-5480-9E1F-B9D475210D86","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Barbell Seated Good Morning","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and a barbell resting on your upper back.","Keep your back straight and your chest up.","Slowly hinge forward at the hips, lowering your torso towards the ground.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"21ED7F09-228B-53A9-AF06-4B5031B0D627","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"405ED3FF-2CFD-57B5-BFCC-4F708B43AF0C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B4EBE9AC-FD90-5BC2-8C71-34749D21723E","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"4437F079-52A0-5DA4-954D-36C8677B619B","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('69A51741-101E-5FB8-9337-7B82FD17E471'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"69A51741-101E-5FB8-9337-7B82FD17E471","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Barbell Seated Overhead Press","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold the barbell with an overhand grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and bring it to shoulder level, with your elbows bent and palms facing forward.","Press the barbell overhead by extending your arms fully.","Pause for a moment at the top, then slowly lower the barbell back to shoulder level.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"BF13A2E6-6A51-547A-A472-A1076A9797C6","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"30FCD07A-981D-5052-9BC3-48F785445063","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"BE99B877-B1A6-5F82-9313-AB448E350D5B","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"23D58C5C-B8CD-5E9F-A18E-2F41F2902CBC","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('6F7FD954-F0CB-5E91-AEC2-1350D5BEA8B4'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"6F7FD954-F0CB-5E91-AEC2-1350D5BEA8B4","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Barbell Seated Overhead Triceps Extension","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and feet flat on the ground.","Hold a barbell with an overhand grip, hands shoulder-width apart, and raise it overhead.","Lower the barbell behind your head by bending your elbows, keeping your upper arms close to your head.","Pause for a moment, then extend your arms to raise the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"AB882130-348F-598E-AA40-CB0AA11819F5","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"6A20710E-8716-5AA4-8A47-72D25241FAC8","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"F7F98330-91F8-5E90-98CC-474FBB436803","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"43AE4B59-155E-5A59-92E4-555ACCAEB8D4","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B6219E40-2AE0-5F62-9C66-9014275ADE74'::uuid, '{"category":"Core","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"B6219E40-2AE0-5F62-9C66-9014275ADE74","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Barbell Seated Twist","notes":"","plannedSets":3,"proTips":["Sit on a flat bench with your feet flat on the ground and your knees bent.","Hold a barbell with both hands in front of your chest, keeping your elbows slightly bent.","Engage your core and slowly twist your torso to one side, keeping your back straight.","Pause for a moment at the end of the twist, then slowly rotate back to the starting position.","Repeat the twist to the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"930598DE-FEB1-59AC-8A08-9E533753C384","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"6F417A6D-BF2A-5904-858D-5236847C3B85","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"07BCC48C-1A92-5FC7-A1C7-BA5BB43D699B","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"013E9DAB-9F26-578D-A177-A80D14F92C7C","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2E3358E1-A30F-59B3-9870-7902463210D7'::uuid, '{"category":"Back","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"2E3358E1-A30F-59B3-9870-7902463210D7","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Traps","Shoulders"],"name":"Barbell Shrug","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell in front of you with an overhand grip.","Keep your arms straight and your back straight throughout the exercise.","Lift your shoulders up towards your ears as high as possible, squeezing your traps at the top.","Hold for a moment, then slowly lower your shoulders back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"72EE785E-7F82-55E3-B448-2A2E79CA544E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"4BF2D518-63BD-5AB1-B7A8-445A11964E06","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"38FF08AB-627A-5600-97FE-EE31EF1390B8","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"80E2EC37-3DA0-5231-924A-6D9E7C3524B7","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3064D585-5E63-530C-B0F7-0340C0AA37DA'::uuid, '{"category":"Core","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"3064D585-5E63-530C-B0F7-0340C0AA37DA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Barbell Side Bent V. 2","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell with both hands, palms facing down.","Keep your back straight and core engaged throughout the exercise.","Slowly bend your torso to the right side, lowering the barbell towards your right knee.","Pause for a moment, then return to the starting position.","Repeat the movement on the left side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"37A9348A-6F97-568F-AECA-7EA954FB3A13","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"E9F3133B-F693-5C26-B1A0-5065FCF67566","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"080F3B93-0EFB-566E-AC63-EB56B8541CC8","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"DBBAF261-534E-57B4-B64F-6DF21FEE665E","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CBB37EF5-EB8C-5924-9A30-536BEF5B546B'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"CBB37EF5-EB8C-5924-9A30-536BEF5B546B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Barbell Side Split Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.","Hold a barbell across your upper back, resting it on your traps.","Engage your core and keep your chest up as you lower your body down into a squat position, bending at the knees and hips.","As you lower, push your knees out to the sides and keep your weight on your heels.","Lower until your thighs are parallel to the ground, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"910C58D9-450E-5DC0-9574-C40570B4C4ED","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"E6940E06-754A-50CE-A541-04271AEB3FB0","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"CF3053DA-2761-503A-A032-961FB571D2A1","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"4E775A97-C630-5590-990A-5AD6F8C567AC","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('71BAD481-8F3D-5064-98BE-075774E57046'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"71BAD481-8F3D-5064-98BE-075774E57046","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Barbell Side Split Squat V. 2","notes":"","plannedSets":3,"proTips":["Stand with your feet wider than shoulder-width apart, toes pointing slightly outwards.","Hold a barbell across your upper back, resting it on your shoulders.","Take a big step to the side with your right foot, keeping your left foot planted.","Bend your right knee and lower your body down into a squat position, keeping your chest up and your back straight.","Push through your right heel to return to the starting position.","Repeat on the other side, stepping out with your left foot.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"10AA7EDC-84B3-582E-A57D-39B3A4B3D469","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"AA8ED948-4E2A-5AC3-9233-20B6407C54DA","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"3987F62A-A06B-5C49-BEBB-CB66A14AC169","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D18C06A7-9B9B-5432-A2DE-945BC5D4D38E","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('57FE221F-12DD-5EC8-AB02-DE0C5A4B85D5'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"57FE221F-12DD-5EC8-AB02-DE0C5A4B85D5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Barbell Single Leg Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet hip-width apart, holding a barbell in front of your thighs with an overhand grip.","Shift your weight onto your left foot and lift your right foot slightly off the ground.","Hinge forward at the hips, keeping your back straight and your right leg extended behind you for balance.","Lower the barbell towards the ground, keeping it close to your body and your left leg slightly bent.","Pause for a moment at the bottom, then engage your glutes and hamstrings to lift your torso back up to the starting position.","Repeat for the desired number of repetitions, then switch sides."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"1DE632BA-43F3-545A-9AAA-8A1798A8B35F","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"D1BB2856-F8E1-550B-AC68-F422E214A5C5","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"0514FF80-1535-5C13-9251-BD3B87CA048B","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"38BC3ED8-13EE-5C24-9B3D-F8841E0E3000","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B846507D-F5AA-52C7-8E88-AEF91B5C0D60'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"B846507D-F5AA-52C7-8E88-AEF91B5C0D60","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Barbell Single Leg Split Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a barbell across your upper back.","Take a large step forward with one leg, keeping your torso upright.","Lower your body by bending your front knee and hip, while keeping your back leg straight.","Continue lowering until your front thigh is parallel to the ground.","Pause for a moment, then push through your front heel to return to the starting position.","Repeat for the desired number of repetitions, then switch legs."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"002EF333-D7E1-5A59-A30D-504A0F072249","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"7DE9FA00-54DA-564A-B580-95873C40B65A","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"86437EDE-D1B0-5BD5-92BC-F16222B719D5","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"4BE9557E-A6FA-595A-AF22-394237963596","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('7179EE6C-82C8-54E3-A5FF-E8B7274B9A1F'::uuid, '{"category":"Core","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"7179EE6C-82C8-54E3-A5FF-E8B7274B9A1F","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Hip Flexors"],"name":"Barbell Sitted Alternate Leg Raise","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back straight and hold a barbell across your thighs.","Keeping your legs straight, lift one leg up as high as possible while keeping the other leg on the ground.","Lower the raised leg back down and repeat with the other leg.","Continue alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"025D295D-4046-57E8-9A76-73F8A0D3CA48","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"51D858AB-B885-5AF8-ADEF-4F405F6F8683","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"6A8EB38B-F3D3-5C67-B631-9D81A6BDC116","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"1C826888-E5D6-5F59-82B1-42D5A98BEB8C","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('07B3C09A-A552-568F-B0A3-81CA964983B3'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"07B3C09A-A552-568F-B0A3-81CA964983B3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Core"],"name":"Barbell Skier","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell in front of your thighs with an overhand grip.","Bend your knees slightly and hinge forward at the hips, keeping your back straight and chest up.","Simultaneously lift the barbell up towards your shoulders while jumping slightly off the ground.","As you reach the top of the movement, quickly reverse the motion and lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"256E4438-25BB-5DB8-9591-6EE80B51E0F4","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"0D494CD2-72E0-560D-A398-53AF4555ED5B","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"BBAD2A8E-BFB7-5E9A-93A3-F31F24F4D495","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"2ACDC93E-C72C-5B7D-B074-B5CC4BF3800C","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BC51B6A8-BF27-5AAC-A1F1-386CB151BBFE'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"BC51B6A8-BF27-5AAC-A1F1-386CB151BBFE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Barbell Speed Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, toes slightly turned out.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you lower your hips back and down, as if sitting into a chair.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Drive through your heels to stand back up, squeezing your glutes at the top.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"C4807DF0-C679-5DB0-8E04-BBE3F5D32CFE","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"F55B6535-8744-55C3-9121-2F763025839D","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"2E787C04-C14B-579E-9715-95A1D08259E5","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"845B887F-4472-5531-A3F7-7C924A95ADAD","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B3D69058-27F5-5D74-8CC7-4DA9E8AEA210'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"B3D69058-27F5-5D74-8CC7-4DA9E8AEA210","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Barbell Split Squat V. 2","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.","Take a large step forward with your right foot, keeping your torso upright.","Lower your body by bending your knees and hips until your right thigh is parallel to the ground.","Pause for a moment, then push through your right heel to return to the starting position.","Repeat with your left leg forward for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"89E72225-9122-5674-B97B-45A6DAD38010","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"52B41F70-2D93-5AA5-B28E-DC5D0EC1FA6C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"51481A19-EB6F-5E04-90ED-23A597A6656D","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"BA55FCFE-33DB-51BE-AAE6-67488A3B7BB2","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('FCB2CA07-66CB-5F1D-8663-25F669440B09'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"FCB2CA07-66CB-5F1D-8663-25F669440B09","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Barbell Squat (On Knees)","notes":"","plannedSets":3,"proTips":["Start by kneeling on the ground with your knees hip-width apart and your toes pointing forward.","Place a barbell across your shoulders, gripping it with an overhand grip and your hands slightly wider than shoulder-width apart.","Engage your core and keep your chest lifted as you slowly lower your body down by bending your knees, keeping your back straight.","Continue lowering until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"38574F9C-F59B-5233-9F34-B739AAF48126","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"0B0D27B9-561B-50C6-89BE-FDB7927E209A","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"C5A6BC5D-DC34-5B76-9200-8A7C1CCBD71F","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"2A28A4CE-2ADE-55B8-A6BC-B672D74D0484","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('711F4A38-3C76-5C94-A0EB-C19EC1103153'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"711F4A38-3C76-5C94-A0EB-C19EC1103153","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Barbell Squat Jump Step Rear Lunge","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart, holding a barbell across your upper back.","Lower your body into a squat position by bending your knees and pushing your hips back.","Explode upwards, jumping off the ground as high as you can.","Land softly on your feet and immediately step back with one leg into a reverse lunge.","Lower your body down until your front thigh is parallel to the ground, keeping your back straight.","Push through your front heel to return to the starting position.","Repeat the jump and lunge sequence on the other leg.","Continue alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"9EA7F9F7-AF7B-5E58-83C6-B048643FD73F","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"3AB0F83A-3022-571C-9C66-B9EFEBB40A6F","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B48298EC-3338-5A81-98E0-A6A436C0785D","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"91C1959B-24AF-5D92-9F04-42F6A99721F0","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('56E71DAB-21B5-5995-A60D-77ED4C6DF47B'::uuid, '{"category":"Core","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"56E71DAB-21B5-5995-A60D-77ED4C6DF47B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Shoulders","Lower Back"],"name":"Barbell Standing Ab Rollerout","notes":"","plannedSets":3,"proTips":["Stand upright with your feet shoulder-width apart and hold the barbell with both hands in front of your thighs.","Engage your core and slowly roll the barbell down towards the ground, keeping your back straight and your arms extended.","Continue rolling the barbell forward until your body is fully extended and your hands are directly above your head.","Pause for a moment, then slowly roll the barbell back towards your thighs, maintaining control and keeping your core engaged.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"BED47188-2F40-5BB6-B0A7-AD3707A38D51","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"9762E79D-12F1-5F46-81FD-6836916F2DFC","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"8B868DA3-E1D2-53C6-BB47-DC4DC8CAB787","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"6685D4B1-DEC7-5CC2-BFA8-101468C6431B","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('DE6B402B-198E-578D-A408-559F989B5823'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"DE6B402B-198E-578D-A408-559F989B5823","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Shoulders"],"name":"Barbell Standing Back Wrist Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip.","Rest the barbell on the back of your hands with your palms facing down and your fingers pointing towards your body.","Keeping your upper arms stationary, exhale and curl your wrists upwards as far as possible.","Hold the contracted position for a brief pause, then inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"57494ADF-A26A-52AA-8039-148FB1A326EA","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"14DAFA28-E379-5BE0-9D1B-BE53CEE53E66","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"5539336F-C1D0-5A6B-8782-C784EDFA57B5","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"10D270D6-CC0A-5F65-B19D-4C723846252B","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E9B84555-DC2D-5070-B6B3-810C591786F2'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"E9B84555-DC2D-5070-B6B3-810C591786F2","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Barbell Standing Bradford Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the barbell in front of your shoulders with an overhand grip.","Press the barbell overhead, fully extending your arms.","Lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"3DADD3DA-B33C-5B3C-8DB5-381BBCCD6E73","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"83B8CAC1-B3DD-5C09-BA2E-24D302E3C8D8","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"5EAB5293-3E9D-51BD-8346-259B5F553C1B","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"9EA322EC-584A-5856-9FEB-BF620DDB7B33","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3E75C354-3DB1-52EF-AEC8-FC1DC2F602D6'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"3E75C354-3DB1-52EF-AEC8-FC1DC2F602D6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Barbell Standing Calf Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and place a barbell across your upper back.","Raise your heels off the ground as high as possible, using only your toes.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"20ED8350-DF2B-5286-9054-AF9EAE4B03F4","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"75BB4D93-D0E5-57FD-BF25-4BDCB8437DA1","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"A2B18D91-73B8-5898-A8B5-E718A81B77F0","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"2EC86B17-ACE3-57D7-88E0-4FFDD49CC238","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('2FAB7139-A607-54DA-BE5D-CA64948375AC'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"2FAB7139-A607-54DA-BE5D-CA64948375AC","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Standing Close Grip Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, hands close together.","Keep your elbows close to your torso and your upper arms stationary throughout the movement.","Exhale as you curl the weights while contracting your biceps. Continue to raise the bar until your biceps are fully contracted and the bar is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale as you slowly begin to bring the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"0F41FAE8-9BB7-5758-A316-743EAF644703","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"0B07C965-710E-5614-95C1-FFF184F5EF32","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"A551D93F-F16C-5C25-A46B-8FFD4A9480EE","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"CB3231DD-6979-5196-871E-7DD1024BC84E","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('EE01BDE8-A064-51F1-96DC-925E54685950'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"EE01BDE8-A064-51F1-96DC-925E54685950","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Barbell Standing Close Grip Military Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, hands slightly closer than shoulder-width apart.","Lift the barbell to shoulder height, keeping your elbows close to your body.","Press the barbell overhead, extending your arms fully.","Lower the barbell back to shoulder height.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"834E0A78-CC04-5206-B7FB-E7FDFB8BD5D7","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"97526F7C-9BC7-5B08-8457-D618947DB6FA","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"E52F25F0-E492-556F-A566-D67B363ED6E0","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E3E2AEE4-F0AB-5AC7-9011-A7EF09DFABF8","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('C4F70711-83C1-596F-AB3F-B799A102C612'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"C4F70711-83C1-596F-AB3F-B799A102C612","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Standing Concentration Curl","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell in one hand, palm facing up.","Rest your opposite hand on your thigh for support.","Keeping your upper arm stationary, exhale and curl the weight up towards your shoulder.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the weight back down to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"2F46924D-CBBC-500B-9817-195F54BF9893","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"F2A9E212-CA93-5E32-BAD9-2DCABE0D51C5","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"0414DCBB-2958-5FCE-A25A-C57CA418ECE7","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D97B1EF5-6E0E-5F73-8A6B-E73728432E84","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('51399E37-39D1-5BD3-97C1-ACEE749EBDCA'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"51399E37-39D1-5BD3-97C1-ACEE749EBDCA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Barbell Standing Front Raise Over Head","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart, holding a barbell in front of your thighs with an overhand grip.","Keep your back straight and engage your core.","Slowly raise the barbell in front of you, keeping your arms straight and your palms facing down.","Continue lifting until the barbell is slightly above shoulder level.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"87C66133-CCBC-5121-994F-A31A7372BE5F","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"B5708102-CC18-577C-BC8F-8DC2CD73096D","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"200505FF-A517-5869-9F1A-7BB5BBF20A07","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"7A4263B5-7530-5718-AB76-8BD5729B99B9","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A9E34279-AEF2-5918-ACC3-6B1F5D56F8C6'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"A9E34279-AEF2-5918-ACC3-6B1F5D56F8C6","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Glutes"],"name":"Barbell Standing Leg Calf Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and place a barbell across your upper back.","Raise your heels off the ground as high as possible, using your calves.","Pause for a moment at the top, then slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"FE51A2E4-17F1-55CF-AC30-BACD8F842D5E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"8EB0B2B9-7BFF-5755-A8FC-656C60A7B52F","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"53BC6268-8F27-515C-BBA8-D699DE69D51C","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"0D5D8F82-E078-5657-AA78-CDB56B5359F6","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('E43ED234-B30D-56AD-98DC-823EE016508E'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"E43ED234-B30D-56AD-98DC-823EE016508E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Shoulders"],"name":"Barbell Standing Overhead Triceps Extension","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip.","Raise the barbell overhead, fully extending your arms.","Keeping your upper arms close to your head, slowly lower the barbell behind your head by bending your elbows.","Pause for a moment, then raise the barbell back to the starting position by extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"A9D4D900-E0D1-5AA9-A11B-31EFF3D6920E","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"2FE45230-330C-54CD-99DD-CD6B85607EB6","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"A17A3D20-2F5B-52B8-9953-1A42EE468FA2","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"9A152841-F577-5B14-848D-83F6821752AE","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('232E4C89-D608-5E27-A8EB-5439FE48CD1C'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"232E4C89-D608-5E27-A8EB-5439FE48CD1C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Standing Reverse Grip Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a barbell with an underhand grip, palms facing up.","Keep your elbows close to your torso and your upper arms stationary.","Exhale and curl the weights while contracting your biceps, bringing the barbell as close to your shoulders as possible.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"813E7550-B218-58FA-A0C6-A10613F4BEFC","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"EF6B5C7F-FEAA-5424-9A6C-7D3186863883","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"0351F813-E815-5011-B141-79EA2877439C","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"655DB074-AF4B-5248-BCAF-3E0CD1F3BB1D","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('68C0BF4D-5B68-5269-8A77-02BF0A4D5DE3'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"68C0BF4D-5B68-5269-8A77-02BF0A4D5DE3","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Calves","Hamstrings","Quadriceps"],"name":"Barbell Standing Rocking Leg Calf Raise","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell across your upper back.","Raise your heels off the ground as high as possible, balancing on the balls of your feet.","Slowly lower your heels back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"AE199E6A-98D7-5EE1-9526-0C055BBC429D","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"4394DA99-87B4-5E49-AFA5-67E5DFA57A2C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"BDD7967B-1744-52D8-B92E-D87274AEE24B","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D33B2D53-2F3B-5C20-AD8D-6275801D1719","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3C700142-7E71-5AA4-9852-BC450E2C6E4C'::uuid, '{"category":"Core","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"3C700142-7E71-5AA4-9852-BC450E2C6E4C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Lower Back"],"name":"Barbell Standing Twist","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell in front of your chest with both hands, palms facing down.","Engage your core and keep your back straight throughout the exercise.","Slowly twist your torso to the right, pivoting on your feet and hips, while keeping your lower body stable.","Pause for a moment at the end of the twist, then slowly return to the starting position.","Repeat the twist to the left side.","Continue alternating twists for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"7505B041-D331-53F8-81DD-7729CFC5FFF5","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"8C5CCFF3-5539-52C6-AEAC-915E5406DCC9","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"C96DC967-D58A-5A2A-9C4A-CEB23E9B5DE9","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"3162ABDD-6D95-5C6F-B77B-84B9D236FDF8","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('D02EF5F9-E96B-5EB6-97E6-2553411AEC69'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"D02EF5F9-E96B-5EB6-97E6-2553411AEC69","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Barbell Standing Wide Grip Biceps Curl","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell with an underhand grip, hands wider than shoulder-width apart.","Keep your back straight and your elbows close to your torso.","Exhale and curl the barbell up towards your shoulders, keeping your upper arms stationary.","Pause for a moment at the top, squeezing your biceps.","Inhale and slowly lower the barbell back to the starting position, fully extending your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"0A12A512-AE24-5CDA-8947-FEFFF30ACAA6","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"6827AA37-328B-5EF0-85FF-3581C2AF637A","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"3818D55B-47C9-59C6-9492-5061CC2B1AC7","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"0E89CB78-5CBB-550C-B617-ACF731957BB3","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('72D22EB4-5D37-5228-AA4F-35692CF0579C'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"72D22EB4-5D37-5228-AA4F-35692CF0579C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Triceps","Upper Back"],"name":"Barbell Standing Wide Military Press","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold the barbell with an overhand grip, slightly wider than shoulder-width.","Lift the barbell to shoulder height, keeping your elbows slightly in front of the bar.","Press the barbell overhead, extending your arms fully.","Lower the barbell back to shoulder height and repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"9698B0D7-12BA-5F7A-AD7C-6E7C4EB9BFC6","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"2A02ACA9-411E-5FB4-9A2E-55AC87BC278B","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"8BA672F3-01BC-58CB-A9EF-0A520355A93C","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"0A2D4027-CDC3-58F1-B646-6698A8D1B562","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9691B4E2-B2E5-5183-A3CF-D673F43CD064'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"9691B4E2-B2E5-5183-A3CF-D673F43CD064","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Barbell Standing Wide-Grip Curl","notes":"","plannedSets":3,"proTips":["Stand up straight with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart.","Let the barbell hang at arm''s length in front of your thighs, with your palms facing away from your body.","Keeping your upper arms stationary, exhale and curl the barbell upward by contracting your biceps.","Continue to raise the barbell until your biceps are fully contracted and the barbell is at shoulder level.","Hold the contracted position for a brief pause as you squeeze your biceps.","Inhale and slowly begin to lower the barbell back to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"3ACAED48-356E-5A27-BFC4-55CAE0496961","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"8352350C-1D63-5A65-84A7-9A610726D418","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"7C5B61B3-3918-5499-AF6B-72D84734F18B","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"AC112CD4-5018-5B8B-9592-974A8BFDA1A1","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BBBA9ED6-0BB6-5C34-A6CA-1EAAA83B15AA'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"BBBA9ED6-0BB6-5C34-A6CA-1EAAA83B15AA","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Barbell Step-Up","notes":"","plannedSets":3,"proTips":["Stand in front of a bench or step with a barbell resting on your upper back.","Place one foot on the bench or step, ensuring your entire foot is in contact with the surface.","Push through your heel and step up onto the bench or step, fully extending your hip and knee.","Pause briefly at the top, then lower yourself back down to the starting position.","Repeat with the opposite leg.","Continue alternating legs for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"AA546B29-71DD-5FA8-AE2E-D53B1A8C4949","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"2A5919EE-B2F7-5AEE-AD89-0028A1A4973E","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"97504256-61DD-5AEF-A99E-5A7A748777E6","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"F50EDBAF-90DC-5EB3-A6A1-FCA284EF056A","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('803C608B-ED1C-593C-88D1-25F29A8E2E85'::uuid, '{"category":"Legs","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"803C608B-ED1C-593C-88D1-25F29A8E2E85","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Lower Back"],"name":"Barbell Stiff Leg Good Morning","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your knees slightly bent.","Hold the barbell across your upper back, resting it on your traps.","Keeping your back straight, hinge forward at the hips, pushing your glutes back.","Lower your torso until it is parallel to the ground, feeling a stretch in your hamstrings.","Engage your glutes and hamstrings to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"CA93F47C-AD51-5A5F-B5E9-93FCEC8BE07D","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"5E8A835B-DB29-57AD-B8B4-362EC307E14D","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"7A93241E-9733-5A1F-B3DF-E4EEAD5E3FEB","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"3277EADC-61AE-5C11-905A-EF87EB0C5590","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1731AEA7-DAF3-5140-B7CF-735C3D29ABCE'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"1731AEA7-DAF3-5140-B7CF-735C3D29ABCE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Hamstrings","Glutes","Lower Back"],"name":"Barbell Straight Leg Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your toes pointing forward.","Hold the barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Bend at your hips and lower the barbell towards the ground, keeping your back straight and your knees slightly bent.","Lower the barbell until you feel a stretch in your hamstrings.","Engage your hamstrings and glutes to lift the barbell back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"9588DD1F-FDFB-534F-9AB1-9FCBC45C7D52","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"8802DCC0-1E1C-582D-9E72-6FAA14CC372D","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"136A71ED-E1AB-5086-923D-CD979191ECA0","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"D04C152B-B115-597C-BF37-5ACB41C643E8","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('51F2830F-439C-53B2-BC0C-DC132A079A01'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"51F2830F-439C-53B2-BC0C-DC132A079A01","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Quadriceps","Lower Back"],"name":"Barbell Sumo Deadlift","notes":"","plannedSets":3,"proTips":["Stand with your feet wider than shoulder-width apart, toes pointing outwards.","Place a barbell on the ground in front of you, centered between your feet.","Bend your knees and lower your hips, keeping your back straight and chest up, to grip the barbell with an overhand grip.","Engage your core and drive through your heels to lift the barbell off the ground, extending your hips and knees simultaneously.","As you lift, keep your chest up and back straight, and push your hips forward to fully engage your glutes.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position, maintaining control throughout the movement.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"2EB19D81-6640-5AE4-B22B-38065CBD7C10","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"58488686-CCBA-5911-A264-CBA03E539573","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"21FD136C-0445-5A5C-995A-E893D909F98A","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"92AA655B-5FB5-556B-B94F-8CD3061DB5B4","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('1BC05FA8-0273-5FD6-9EA1-48B56D599109'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"1BC05FA8-0273-5FD6-9EA1-48B56D599109","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Quadriceps","Glutes","Hamstrings","Core"],"name":"Barbell Thruster","notes":"","plannedSets":3,"proTips":["Start by standing with your feet shoulder-width apart, holding a barbell at shoulder height with an overhand grip.","Lower into a squat position by bending your knees and pushing your hips back.","As you reach the bottom of the squat, explosively drive through your heels to stand up, simultaneously pressing the barbell overhead.","Lower the barbell back to shoulder height as you lower back into the squat position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"CF53D22B-0948-52F0-910F-7EFBB1F12668","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"DA19E43D-4FC9-5EFA-A825-1CAE681283BD","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"70CF8B0D-F56C-51D4-92A7-B0B97165D20A","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"0EBEC105-EF85-5AF5-AAF5-0F9AA7905650","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('CE51D0F7-FE96-51C2-A236-945ABA8F272C'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"CE51D0F7-FE96-51C2-A236-945ABA8F272C","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Biceps"],"name":"Barbell Upright Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your back straight and core engaged, exhale and lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"291150AD-155A-5BDE-9945-ED07BAAAEE95","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"5AE47B99-F710-545E-98A1-1DA2E7E9CCB1","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"80385FA2-E9FE-507E-B829-EF542201FAA9","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"90C1F6C3-36E0-57E0-89B4-DE57A9E8F6EE","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('BC871822-14A6-5BC1-807B-4FC027B7256A'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"BC871822-14A6-5BC1-807B-4FC027B7256A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Biceps"],"name":"Barbell Upright Row V. 2","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"CD1E6845-B5A2-5374-BDBB-3B85655E2524","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"0368811C-681C-5604-BEA6-23F47283DF22","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"4967F3EF-5064-5F41-B2BE-E2D0F7316F0D","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"0687930E-16E2-5E07-979B-E84BDF8F3E48","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9C463828-07AC-593D-BB9A-B963B8F80505'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"9C463828-07AC-593D-BB9A-B963B8F80505","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Biceps"],"name":"Barbell Upright Row V. 3","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands slightly wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your core engaged and back straight, exhale as you lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale as you slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"EA01EB24-05BF-50C2-88E6-C47D2ABFE04A","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"5BFC7443-A189-547E-AE2A-DF5D07F4211F","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"71D8E9C2-CD62-5DF8-A665-93119A3CC2FB","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"11D0C9C4-2561-5CA8-ACAE-514310EE13A7","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3C6ACB34-B01D-5885-A1B9-07ADD6422AF9'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"3C6ACB34-B01D-5885-A1B9-07ADD6422AF9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Barbell Wide Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a wide grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Lower the barbell slowly towards your chest, keeping your elbows slightly flared out.","Pause for a moment when the barbell touches your chest, then push it back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"2D508946-C4F9-5BA3-9EA2-063D28A37BE9","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"946CEC2C-4887-5670-913F-E9BF243A8055","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"EE5E8505-B375-5063-B762-AB6A07785B3E","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"B17FFADF-B15E-5BDF-877A-4DADF068F312","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('33A86342-8228-5851-A8DF-79FAC8267350'::uuid, '{"category":"Chest","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"33A86342-8228-5851-A8DF-79FAC8267350","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Triceps","Shoulders"],"name":"Barbell Wide Reverse Grip Bench Press","notes":"","plannedSets":3,"proTips":["Lie flat on a bench with your feet flat on the ground and your back pressed against the bench.","Grasp the barbell with a wide reverse grip, slightly wider than shoulder-width apart.","Lift the barbell off the rack and hold it directly above your chest with your arms fully extended.","Lower the barbell slowly towards your chest, keeping your elbows tucked in and your wrists straight.","Pause for a moment when the barbell touches your chest, then push it back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"4F83EC29-FA20-56C6-8CA2-E9BB83EF9069","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"E7185E0F-89AF-572F-9214-1CCE7B4EFA65","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"3F946A8A-6991-5109-BB03-8D0DF630EE4E","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"9CF06DC6-0340-5A93-98EE-86CD95C5E8B7","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('5C4A51E1-DE45-59B1-B013-036E2A874DE9'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"5C4A51E1-DE45-59B1-B013-036E2A874DE9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Quads","Glutes","Hamstrings","Calves"],"name":"Barbell Wide Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet wider than shoulder-width apart, toes pointing slightly outward.","Hold the barbell across your upper back, resting it on your traps or rear delts.","Engage your core and keep your chest up as you lower your body down into a squat, pushing your hips back and bending your knees.","Lower until your thighs are parallel to the ground, or as low as you can comfortably go.","Pause for a moment at the bottom, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"1A8F705B-DAA9-5790-B8AF-EE098A439A2B","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"9964BE4D-AF71-56AA-9EFE-E1C718E21A1C","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"2117CAE9-D401-55B2-B785-08FFBC2BFDFB","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"20CAB967-D6C3-50B6-B376-43F3AEDAA743","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('571B3C0D-35F2-563B-B98F-AFD91D53661B'::uuid, '{"category":"Shoulders","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"571B3C0D-35F2-563B-B98F-AFD91D53661B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Traps","Biceps"],"name":"Barbell Wide-Grip Upright Row","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and hold a barbell with an overhand grip, hands wider than shoulder-width apart.","Let the barbell hang in front of your thighs, arms fully extended.","Keeping your back straight, exhale and lift the barbell straight up towards your chin, leading with your elbows.","Pause for a moment at the top, then inhale and slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"D8840124-07FE-5120-87DD-34A911B68BED","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"C30E9798-5225-5D80-BB68-6B3CDCD08690","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"B6E58C88-2AC1-5369-9D33-050BCD1D7722","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"E4B57050-677D-514E-AFEE-EE3E8D071EE2","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('0E5DC2D1-6D85-5F3B-BD5F-0AC5B6D06A28'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"0E5DC2D1-6D85-5F3B-BD5F-0AC5B6D06A28","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Barbell Wrist Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and your forearms resting on your thighs, holding a barbell with an underhand grip.","Allow the barbell to roll down to your fingertips, keeping your wrists straight.","Slowly curl the barbell up towards your forearms by flexing your wrists.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"A148CA40-3C7D-528E-B0F4-BF472A1AF39F","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"F88D693D-23C2-5769-82A0-098760583E99","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"8DB6E63E-B9A8-5FCF-8B6E-A00FB8558428","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"9FF7D6C0-B831-52CD-A2BE-3DC07E44153F","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F9114C07-CCAF-5E5B-9125-4A1FB6B5EA43'::uuid, '{"category":"Arms","difficulty":"Intermediate","equipment":"Barbell","hint":"","id":"F9114C07-CCAF-5E5B-9125-4A1FB6B5EA43","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Forearms","Biceps","Brachialis"],"name":"Barbell Wrist Curl V. 2","notes":"","plannedSets":3,"proTips":["Sit on a bench with your feet flat on the ground and your knees bent.","Hold a barbell with an underhand grip, palms facing up, and your hands shoulder-width apart.","Rest your forearms on your thighs, allowing your wrists to hang off the edge.","Slowly curl your wrists upward, bringing the barbell towards your forearms.","Pause for a moment at the top, then slowly lower the barbell back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"768B9557-900F-5F2A-BBA9-54F515B68D6A","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"B863328C-46F4-5939-9070-4DAB35978BD6","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"75E59404-2CD5-56AE-AB4B-D892A0F833C0","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"C1346468-53D3-50FF-9952-F4E60D384291","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('289A433B-818F-5440-B346-20A630046A6B'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Barbell","hint":"","id":"289A433B-818F-5440-B346-20A630046A6B","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves","Core"],"name":"Barbell Zercher Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and toes slightly turned out.","Hold the barbell in the crooks of your elbows, with your hands gripping the bar for stability.","Engage your core and keep your chest lifted as you lower your hips back and down into a squat position.","Keep your knees in line with your toes and your weight in your heels.","Pause for a moment at the bottom of the squat, then push through your heels to return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"Groove the movement pattern before adding load.","id":"DB9AEF84-535A-5DB8-8972-026432E69431","intensity":"Empty Bar","reps":12,"set":1},{"description":"Explosive concentric phase.","id":"0F7EFDDC-D128-500A-817D-AC3B5D18E37F","intensity":"50% Target Weight","reps":8,"set":2},{"description":"Acclimatize to load without fatigue.","id":"CFAD799D-A5EF-5E29-A01F-3F3DE6093467","intensity":"70% Target Weight","reps":4,"set":3},{"description":"Single feeler rep to prepare the CNS.","id":"50C43272-7B29-5516-97C1-2A6FACDD00F0","intensity":"90% Target Weight","reps":1,"set":4}],"type":"Full Progressive Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('879D9E38-E064-50C9-938E-C885E2C36189'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"879D9E38-E064-50C9-938E-C885E2C36189","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings","Calves"],"name":"Basic Toe Touch","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and your arms by your sides.","Bend forward at the waist, keeping your back straight and your knees slightly bent.","Reach down towards your toes with your hands, keeping your legs as straight as possible.","Pause for a moment at the bottom, then slowly return to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3BC31190-4172-5430-96AE-6BAE757B5088","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('F47FC446-CA1C-528B-94EC-B29F6C0B037D'::uuid, '{"category":"Shoulders","difficulty":"Beginner","equipment":"Rope","hint":"","id":"F47FC446-CA1C-528B-94EC-B29F6C0B037D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Delts","Forearms","Core"],"name":"Battling Ropes","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart and knees slightly bent.","Hold one end of the rope in each hand, with your palms facing each other.","Raise your arms to shoulder height, keeping your elbows slightly bent.","Begin making alternating waves with the ropes by rapidly raising and lowering each arm.","Continue for the desired duration or number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"84F3BDC4-FAB8-5D33-8E78-5C1332EE96D0","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('23A71238-E0C5-591D-893C-B2E0893C5CE0'::uuid, '{"category":"Cardio","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"23A71238-E0C5-591D-893C-B2E0893C5CE0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Cardiovascular System","Core","Shoulders","Triceps"],"name":"Bear Crawl","notes":"","plannedSets":3,"proTips":["Start on all fours with your hands directly under your shoulders and your knees directly under your hips.","Lift your knees slightly off the ground, keeping your back flat and your core engaged.","Move your right hand and left foot forward simultaneously, followed by your left hand and right foot.","Continue crawling forward, alternating your hand and foot movements.","Maintain a steady pace and keep your core tight throughout the exercise.","Continue for the desired distance or time."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[],"type":"No Warmup Required"},"youtubeURL":""}'::jsonb, now()),
  ('AB382300-33F2-5A19-BFA2-F2A0C2B676A0'::uuid, '{"category":"Chest","difficulty":"Beginner","equipment":"Assisted","hint":"","id":"AB382300-33F2-5A19-BFA2-F2A0C2B676A0","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Pectorals","Shoulders","Triceps"],"name":"Behind Head Chest Stretch","notes":"","plannedSets":3,"proTips":["Stand tall with your feet shoulder-width apart.","Interlace your fingers behind your head with your elbows pointing outwards.","Slowly squeeze your shoulder blades together and push your chest forward.","Hold the stretch for 15-30 seconds.","Release the stretch and repeat as desired."],"pulley":"single","repRange":"8–12","type":"Machine","warmupProtocol":{"steps":[{"description":"Move slowly through the full range, no bouncing.","id":"32AFB97B-1D48-5680-BBBA-238EF6C0C2AB","intensity":"Bodyweight","reps":10,"set":1}],"type":"Mobility Sequence"},"youtubeURL":""}'::jsonb, now()),
  ('9AFC21F0-3858-5D9B-A56D-36765EB67854'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9AFC21F0-3858-5D9B-A56D-36765EB67854","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Bench Dip (Knees Bent)","notes":"","plannedSets":3,"proTips":["Sit on the edge of a bench or chair with your hands gripping the edge next to your hips.","Slide your butt off the bench and straighten your legs in front of you, keeping your heels on the ground.","Bend your elbows and lower your body towards the ground, keeping your back close to the bench.","Pause for a moment at the bottom, then push yourself back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"234CFF6C-00F8-5FA4-8A16-BCC35D78662A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('3BF2E4E7-F737-5FB6-99C9-67FEADA8D7E5'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"3BF2E4E7-F737-5FB6-99C9-67FEADA8D7E5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Bench Dip On Floor","notes":"","plannedSets":3,"proTips":["Sit on the edge of a bench or chair with your hands gripping the edge, fingers pointing forward.","Slide your butt off the bench, supporting your weight with your hands.","Lower your body by bending your elbows until your upper arms are parallel to the floor.","Push yourself back up to the starting position by straightening your arms.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3BD15D62-D153-5852-8BE7-A05342226152","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('422C2699-542C-590C-90D0-9ADF041D7C69'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"422C2699-542C-590C-90D0-9ADF041D7C69","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Hamstrings"],"name":"Bench Hip Extension","notes":"","plannedSets":3,"proTips":["Sit on a bench with your back against the bench and your feet flat on the ground.","Place your hands on the bench for support.","Engage your glutes and hamstrings, then lift your hips off the bench until your body forms a straight line from your knees to your shoulders.","Pause for a moment at the top, then slowly lower your hips back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8A66CAF3-3970-53EF-928F-C8B17DB7D1FB","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('9209ACCF-DA19-5580-98B5-64466A71AE9A'::uuid, '{"category":"Back","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"9209ACCF-DA19-5580-98B5-64466A71AE9A","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Lats","Biceps","Forearms"],"name":"Bench Pull-Ups","notes":"","plannedSets":3,"proTips":["Position yourself under a bar or a sturdy horizontal surface that is at chest height.","Grab the bar or surface with an overhand grip, slightly wider than shoulder-width apart.","Hang with your arms fully extended and your body straight.","Pull your chest towards the bar or surface by squeezing your shoulder blades together and bending your elbows.","Continue pulling until your chin is above the bar or surface.","Lower yourself back down to the starting position with control.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"5E59699D-F250-50AF-B171-1EE5A14F272D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('714E20CC-40B3-5137-A228-CF6045D3B5CE'::uuid, '{"category":"Legs","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"714E20CC-40B3-5137-A228-CF6045D3B5CE","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Obliques","Hip Flexors"],"name":"Bent Knee Lying Twist","notes":"","plannedSets":3,"proTips":["Lie flat on your back with your knees bent and feet flat on the ground.","Extend your arms out to the sides, perpendicular to your body.","Keeping your knees together, slowly lower them to one side, aiming to touch the ground with your knees.","Pause for a moment, then engage your core and slowly lift your knees back to the starting position.","Repeat the movement to the other side.","Continue alternating sides for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"4B2B4AEF-76EE-5C1C-B994-207500A81712","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('913D7E4D-498D-505E-AD51-8A8DEF7C0F68'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"913D7E4D-498D-505E-AD51-8A8DEF7C0F68","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms"],"name":"Biceps Leg Concentration Curl","notes":"","plannedSets":3,"proTips":["Sit on a bench with your legs spread apart and your feet flat on the ground.","Hold a dumbbell in one hand and place your elbow on the inside of your thigh, just above the knee.","With your palm facing up, curl the dumbbell towards your shoulder while keeping your upper arm stationary.","Squeeze your biceps at the top of the movement, then slowly lower the dumbbell back to the starting position.","Repeat for the desired number of repetitions, then switch arms."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"8435B985-B2D6-5CE0-876E-9DF8D7AF2A57","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('68082BB2-656A-5EA1-9744-3FF8948EC0A5'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"68082BB2-656A-5EA1-9744-3FF8948EC0A5","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Biceps Narrow Pull-Ups","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your palms facing towards you and your hands shoulder-width apart.","Engage your core and pull yourself up towards the bar, focusing on using your biceps to lift your body.","Pause for a moment at the top, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"13932451-DD65-5BC5-B7D0-38B20E49AF7D","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('132F60DC-980A-5F3E-950A-9F1A64489D14'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"132F60DC-980A-5F3E-950A-9F1A64489D14","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Biceps","Forearms","Shoulders"],"name":"Biceps Pull-Up","notes":"","plannedSets":3,"proTips":["Hang from a pull-up bar with your palms facing away from you and your hands shoulder-width apart.","Engage your core and pull yourself up by bending your elbows, bringing your chest towards the bar.","Pause at the top of the movement, then slowly lower yourself back down to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3E03E041-4B8C-50BE-92B2-809605BC33C5","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('B564F91F-E967-52FD-A948-EEECB2F276F9'::uuid, '{"category":"Arms","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"B564F91F-E967-52FD-A948-EEECB2F276F9","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Triceps","Chest","Shoulders"],"name":"Body-Up","notes":"","plannedSets":3,"proTips":["Start by placing your hands on a raised surface, such as a bench or parallel bars, with your palms facing down and fingers pointing forward.","Extend your legs out in front of you, keeping your heels on the ground and your body straight.","Lower your body by bending your elbows, keeping them close to your sides, until your upper arms are parallel to the ground.","Pause for a moment, then push through your palms to straighten your arms and lift your body back up to the starting position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"66120F12-11A0-5512-BA6D-36C69FB1707A","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('AE42B257-08C8-55CF-A83D-9DA2AFED390E'::uuid, '{"category":"Legs","difficulty":"Advanced","equipment":"Bodyweight","hint":"","id":"AE42B257-08C8-55CF-A83D-9DA2AFED390E","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Glutes","Quadriceps","Hamstrings","Calves"],"name":"Bodyweight Drop Jump Squat","notes":"","plannedSets":3,"proTips":["Stand with your feet shoulder-width apart.","Lower your body into a squat position by bending your knees and pushing your hips back.","Jump up explosively, extending your hips, knees, and ankles.","While in mid-air, quickly bring your feet together.","Land softly on the balls of your feet and immediately drop back into a squat position.","Repeat for the desired number of repetitions."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"FAB44227-0AA5-5F45-81A4-522A8F236C39","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now()),
  ('A9D568FE-790D-5D83-8761-73670F0FFB7D'::uuid, '{"category":"Core","difficulty":"Beginner","equipment":"Bodyweight","hint":"","id":"A9D568FE-790D-5D83-8761-73670F0FFB7D","imageURL":"","isCable":false,"isCustom":false,"isFavorite":false,"musclesTargeted":["Abs","Obliques","Shoulders"],"name":"Bodyweight Incline Side Plank","notes":"","plannedSets":3,"proTips":["Start by lying on your side with your legs extended and stacked on top of each other.","Place your forearm on the ground directly below your shoulder, with your elbow bent at a 90-degree angle.","Engage your core and lift your hips off the ground, creating a straight line from your head to your feet.","Hold this position for the desired amount of time.","Lower your hips back down to the ground and repeat on the other side."],"pulley":"single","repRange":"8–12","type":"Compound","warmupProtocol":{"steps":[{"description":"One light set to find the working range.","id":"3A9C464E-88CA-5539-A58C-02BFE2977C76","intensity":"Light","reps":12,"set":1}],"type":"1-Set Direct Protocol"},"youtubeURL":""}'::jsonb, now())
